var TOPICS_DATA = TOPICS_DATA || {};
TOPICS_DATA["devops-fundamentals"] = TOPICS_DATA["devops-fundamentals"] || {};
TOPICS_DATA["devops-fundamentals"]["devops-what-is-devops"] = {"id":"devops-what-is-devops","title":"What is DevOps","difficulty":"beginner","estimatedMinutes":15,"tldr":["DevOps is a set of practices that combines software development (Dev) and IT operations (Ops) to shorten the development lifecycle.","Goals: faster delivery, higher quality, reduced failure rate, improved collaboration between teams.","DevOps emphasizes automation, continuous delivery, monitoring, and shared ownership of the entire application lifecycle.","DevOps is a cultural and professional movement, not a tool or role — it changes how organizations deliver software."],"laymanDefinition":"DevOps is like a restaurant where the chefs (developers) and waitstaff (operations) work as one team instead of separate groups. The chefs see what customers are saying, and the waitstaff understand how the kitchen works. Together, they serve better food faster and fix problems immediately when they arise.","deepDive":[{"heading":"The DevOps Philosophy","text":"Break down silos between Dev and Ops teams. Shared responsibility for the entire lifecycle from development through production. Automate everything possible. Measure everything. Learn from failures. Iterate rapidly. The Three Ways: Flow (fast left-to-right), Feedback (fast right-to-left), Continuous Learning."},{"heading":"Key DevOps Metrics","text":"Deployment Frequency: how often you deploy to production. Lead Time: time from commit to production. Change Failure Rate: percentage of deployments causing failures. Mean Time to Recovery (MTTR): time to recover from failures. These four metrics define the DORA DevOps capabilities."},{"heading":"CALMS Framework","text":"Culture: collaboration, shared responsibility. Automation: eliminate manual processes. Lean: optimize flow, reduce waste. Measurement: data-driven decisions. Sharing: knowledge and feedback across teams. CALMS assesses DevOps maturity in organizations."}],"interviewAnswer":"DevOps is a cultural and technical movement to deliver value faster and more reliably. Focus on the Three Ways: flow, feedback, and learning. Automate everything. Measure the four key DORA metrics. Break down team silos. DevOps is not a tool or a role — it is a collaborative approach to software delivery.","interviewQuestions":[{"question":"What is DevOps?","answer":"A set of practices combining Dev and Ops to shorten the development lifecycle and deliver high-quality software continuously."},{"question":"What are the four key DORA metrics?","answer":"Deployment Frequency, Lead Time, Change Failure Rate, Mean Time to Recovery (MTTR)."},{"question":"What is the CALMS framework?","answer":"Culture, Automation, Lean, Measurement, Sharing — assesses DevOps maturity."},{"question":"Is DevOps a tool or a role?","answer":"No. DevOps is a cultural and professional movement combining practices, not a specific tool or job title."},{"question":"What are the Three Ways of DevOps?","answer":"Flow (fast left-to-right), Feedback (fast right-to-left), Continuous Learning and Experimentation."},{"question":"What does DevOps emphasize?","answer":"Automation, continuous delivery, monitoring, collaboration, and shared ownership."},{"question":"What is DevOps — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"What is DevOps — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"What is DevOps — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"What is DevOps — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">What is DevOps</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dev</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Developers build</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Ops</text><text x=\"215\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Operations run</text><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Automation</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">CI/CD pipelines</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Monitoring</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Metrics & alerts</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Collaboration</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Shared ownership</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Continuous</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Delivery + Learning</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DevOps</text><text x=\"385\" y=\"162\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Dev + Ops = faster, reliable deliv</text><text x=\"385\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ery. Culture, automation, measurem</text><text x=\"385\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ent, sharing.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">DevOps: Practices combining Dev and Ops to deliver</text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> value faster with higher quality.</text></svg>","codeExamples":[{"title":"DevOps Pipeline Overview","useCase":"CI/CD pipeline stages.","code":"# Typical DevOps pipeline stages\n# Code → Build → Test → Package → Deploy → Monitor\n\n# .github/workflows/devops-pipeline.yml\nname: DevOps Pipeline\non: [push]\njobs:\n  build:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - name: Install dependencies\n        run: npm ci\n      - name: Run tests\n        run: npm test\n      - name: Build\n        run: npm run build\n      - name: Deploy\n        run: ./deploy.sh","description":"A simple CI/CD pipeline automating the build, test, and deploy process."},{"title":"DevOps Culture Manifesto","useCase":"Cultural principles.","code":"# DevOps cultural principles\n# Instead of silos → collaboration\n# Instead of manual → automation\n# Instead of fear of change → embrace change\n# Instead of blame → blameless postmortems\n# Instead of big releases → small frequent deploys\n# Instead of hero culture → shared ownership\n# Instead of separate tools → integrated toolchain\n\n# Key behaviors:\n# - Devs handle their own deployments\n# - Ops provides self-service platforms\n# - Everyone monitors production\n# - Experimentation is encouraged\n# - Fail fast, learn faster","description":"DevOps culture emphasizes collaboration, automation, shared responsibility, and blameless learning."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What does DevOps combine?","options":["Design and Development","Development and Operations","Testing and Deployment","Security and Compliance"],"answer":1,"explanation":"DevOps combines Development (Dev) and Operations (Ops)."},{"question":"Which is NOT a DORA metric?","options":["Deployment Frequency","Lead Time","Code Coverage","MTTR"],"answer":2,"explanation":"Code Coverage is not one of the four DORA metrics."},{"question":"What does CALMS stand for?","options":["Culture, Automation, Lean, Measurement, Sharing","Code, Analyze, Learn, Monitor, Secure","CI/CD, Agile, Lean, Metrics, Security","Collaborate, Automate, Log, Monitor, Scale"],"answer":0,"explanation":"CALMS = Culture, Automation, Lean, Measurement, Sharing."},{"question":"What is DevOps — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"What is DevOps — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"What is DevOps — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"What is DevOps — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"What is DevOps — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"What is DevOps — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"What is DevOps — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-lifecycle"] = {"id":"devops-lifecycle","title":"DevOps Lifecycle","difficulty":"beginner","estimatedMinutes":15,"tldr":["The DevOps lifecycle is a continuous loop of phases that governs how software moves from idea to production and back.","Phases: Plan → Code → Build → Test → Release → Deploy → Operate → Monitor → Feedback → (back to Plan).","Unlike traditional linear SDLC, the DevOps lifecycle is infinite and continuous, with feedback loops at every stage.","Each phase has specific tools and practices: Jira (Plan), Git (Code), Jenkins/GitHub Actions (Build/Test), Docker/K8s (Deploy), Prometheus (Monitor)."],"laymanDefinition":"The DevOps lifecycle is like a perpetual motion machine for software. Imagine a factory that takes raw ideas, turns them into products, ships them, watches how customers use them, and sends improvement notes back to the design team — all automatically, all the time.","deepDive":[{"heading":"Plan Phase","text":"Define requirements, prioritize work, plan sprints. Tools: Jira, Confluence, Trello, Aha!. Practices: user stories, backlog grooming, sprint planning. Output: prioritized, estimated work items ready for development."},{"heading":"Code, Build, Test Phase","text":"Code: developers write and commit code (Git). Build: compile code, resolve dependencies (Maven, npm, Gradle). Test: automated unit, integration, and security tests (Jest, JUnit, Selenium). This is where CI runs — every commit triggers build + test."},{"heading":"Release, Deploy, Operate Phase","text":"Release: approve and prepare for production (change management, feature flags). Deploy: push to production (blue-green, canary, rolling). Operate: keep the application running (Kubernetes, Docker, logging)."},{"heading":"Monitor and Feedback Phase","text":"Monitor: track metrics, logs, traces (Prometheus, Grafana, ELK, Datadog). Feedback: alerts, dashboards, incident response, postmortems. Feedback loops back to Plan — improvements feed into the next iteration. Continuous improvement is built into the cycle."}],"interviewAnswer":"The DevOps lifecycle is an infinite loop: Plan → Code → Build → Test → Release → Deploy → Operate → Monitor → Feedback → back to Plan. Each phase feeds into the next, and feedback loops ensure continuous improvement. Automation is key at every stage.","interviewQuestions":[{"question":"What are the phases of the DevOps lifecycle?","answer":"Plan → Code → Build → Test → Release → Deploy → Operate → Monitor → Feedback."},{"question":"How is the DevOps lifecycle different from traditional SDLC?","answer":"It is continuous (infinite loop), not linear. Feedback loops connect every phase."},{"question":"What happens in the Monitor phase?","answer":"Track metrics, logs, traces. Set up alerts. Incident response. Gather feedback for improvement."},{"question":"What is the purpose of feedback loops?","answer":"To continuously improve by feeding observations from later phases back into planning and development."},{"question":"What phase handles CI (Continuous Integration)?","answer":"Code, Build, Test — every commit triggers automated build and tests."},{"question":"What tools are used in the Monitor phase?","answer":"Prometheus, Grafana, ELK Stack, Datadog, New Relic, Sentry."},{"question":"DevOps Lifecycle — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"DevOps Lifecycle — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"DevOps Lifecycle — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"DevOps Lifecycle — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">DevOps Lifecycle</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Plan</text><text x=\"60\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Requirements</text><rect x=\"115\" y=\"35\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"165\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Code</text><text x=\"165\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Git</text><rect x=\"220\" y=\"35\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build</text><text x=\"270\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Compile</text><rect x=\"325\" y=\"35\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"375\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Test</text><text x=\"375\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated</text><line x1=\"110\" y1=\"48\" x2=\"115\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"215\" y1=\"48\" x2=\"220\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"320\" y1=\"48\" x2=\"325\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Release</text><text x=\"60\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Approve</text><rect x=\"115\" y=\"65\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"165\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy</text><text x=\"165\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Push to prod</text><rect x=\"220\" y=\"65\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"270\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Operate</text><text x=\"270\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Run</text><rect x=\"325\" y=\"65\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"375\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Monitor</text><text x=\"375\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Metrics</text><line x1=\"110\" y1=\"78\" x2=\"115\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"215\" y1=\"78\" x2=\"220\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"320\" y1=\"78\" x2=\"325\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"425\" y1=\"78\" x2=\"10\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"100\" width=\"415\" height=\"30\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"217.5\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Feedback Loop</text><text x=\"217.5\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Continuous improvement from monitoring back to planning</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">DevOps Lifecycle: Infinite loop of Plan → Code → B</text><text x=\"240\" y=\"182\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">uild → Test → Release → Deploy → Operate → Monitor</text><text x=\"240\" y=\"194\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> → Feedback.</text></svg>","codeExamples":[{"title":"Lifecycle Diagram as Code","useCase":"Mermaid DevOps lifecycle.","code":"```mermaid\ngraph LR\n  Plan --> Code\n  Code --> Build\n  Build --> Test\n  Test --> Release\n  Release --> Deploy\n  Deploy --> Operate\n  Operate --> Monitor\n  Monitor -->|Feedback| Plan\n```\n\n# Embedded in documentation\n# Shows the infinite loop nature","description":"Mermaid diagram representing the DevOps lifecycle as an infinite loop."},{"title":"Lifecycle Toolchain Mapping","useCase":"Tools per phase.","code":"# DevOps Lifecycle Toolchain\n\n# Plan:     Jira, Confluence, Notion, Asana\n# Code:     Git, GitHub, GitLab, Bitbucket\n# Build:    Jenkins, GitHub Actions, CircleCI\n# Test:     Jest, JUnit, Selenium, SonarQube\n# Release:  Artifactory, Nexus, feature flags\n# Deploy:   Docker, Kubernetes, Terraform, Ansible\n# Operate:  K8s, Docker Swarm, ECS, EKS\n# Monitor:  Prometheus, Grafana, ELK, Datadog\n# Feedback: PagerDuty, OpsGenie, Statuspage","description":"Mapping of common tools to each phase of the DevOps lifecycle."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the first phase of the DevOps lifecycle?","options":["Code","Plan","Deploy","Monitor"],"answer":1,"explanation":"Plan is the first phase — requirements and prioritization before any code is written."},{"question":"How is the DevOps lifecycle different from traditional SDLC?","options":["Same thing","It is continuous, not linear","It has fewer phases","It has more phases"],"answer":1,"explanation":"The DevOps lifecycle is an infinite continuous loop, unlike the linear traditional SDLC."},{"question":"What connects the Monitor phase back to Plan?","options":["Alerts","Feedback loops","Dashboards","Incidents"],"answer":1,"explanation":"Feedback loops from monitoring drive improvements back into planning."},{"question":"DevOps Lifecycle — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"DevOps Lifecycle — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"DevOps Lifecycle — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"DevOps Lifecycle — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"DevOps Lifecycle — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"DevOps Lifecycle — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"DevOps Lifecycle — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-culture"] = {"id":"devops-culture","title":"DevOps Culture","difficulty":"beginner","estimatedMinutes":15,"tldr":["DevOps culture is the set of behaviors, values, and practices that enable the DevOps transformation in an organization.","Core values: collaboration, automation, measurement, sharing, trust, blamelessness, and continuous improvement.","DevOps culture replaces \"throw it over the wall\" mentality with shared ownership of the entire application lifecycle.","Key cultural shifts: devs handle operations, ops influence design, failures are learning opportunities, experimentation is encouraged."],"laymanDefinition":"DevOps culture is like a sports team where everyone plays both offense and defense. In traditional IT, developers throw the ball (code) over the wall to operations who then try to run with it. In DevOps culture, everyone is on the same field, wearing the same jersey, and responsible for both scoring and defending.","deepDive":[{"heading":"Blameless Postmortems","text":"When something fails, the focus is on \"what broke\" not \"who broke it\". Root cause analysis of systems and processes, not individuals. Document what happened, why, and what to change. Share learnings broadly. No disciplinary action for honest mistakes. This encourages reporting issues without fear."},{"heading":"Shared Ownership","text":"Developers are on-call for their code. Operations has input on architecture. Everyone shares the pager. \"You build it, you run it\" (Amazon principle). Shared ownership means no handoffs. Teams own services end-to-end from development through production."},{"heading":"Psychological Safety","text":"Team members feel safe to take risks and admit mistakes. Experimentation is encouraged — not all experiments succeed. Failure is treated as a learning opportunity. New ideas are welcomed. Questions are encouraged. This is the foundation of high-performing DevOps teams."},{"heading":"Continuous Improvement Culture","text":"Kaizen (Japanese: \"change for better\"). Small incremental improvements daily. Retrospectives after incidents and releases. Regular feedback loops. Metrics-driven improvement. Culture of learning: training, conferences, internal knowledge sharing. Experimentation with new tools and processes."}],"interviewAnswer":"DevOps culture is the foundation of all DevOps practices. Without the right culture, tools and automation alone cannot transform an organization. Focus on blamelessness, shared ownership, psychological safety, and continuous improvement. The best DevOps tooling cannot fix a broken culture.","interviewQuestions":[{"question":"What is DevOps culture?","answer":"Behaviors, values, and practices enabling DevOps: collaboration, blamelessness, shared ownership, and continuous improvement."},{"question":"What is a blameless postmortem?","answer":"An incident review focusing on system/process failures, not individual blame. Learn from failures without punishment."},{"question":"What does \"you build it, you run it\" mean?","answer":"Developers are responsible for their code in production, including on-call and incident response."},{"question":"What is psychological safety?","answer":"Team members feel safe to take risks, admit mistakes, and ask questions without fear of negative consequences."},{"question":"What is Kaizen?","answer":"Japanese philosophy of continuous improvement through small, incremental changes."},{"question":"Is culture or tools more important in DevOps?","answer":"Culture. Tools support the culture but cannot replace it. The best tools with a bad culture will fail."},{"question":"DevOps Culture — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"DevOps Culture — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"DevOps Culture — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"DevOps Culture — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">DevOps Culture</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Collaboration</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Dev + Ops together</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Blameless</text><text x=\"65\" y=\"73\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fix process, not peo</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ple</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Shared Ownership</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Build it, run it</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Safety</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Experiment freely</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Improvement</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Kaizen daily</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DevOps Culture</text><text x=\"385\" y=\"162\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Collaboration, blamelessness, shar</text><text x=\"385\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ed ownership, psychological safety</text><text x=\"385\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">, continuous improvement.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">DevOps Culture: The foundation of all DevOps pract</text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ices. Trust, safety, collaboration, and learning.</text></svg>","codeExamples":[{"title":"Blameless Postmortem Template","useCase":"Structured incident review.","code":"---\ntitle: Postmortem Template\n---\n\n## Summary\n- Date: YYYY-MM-DD\n- Severity: SEV1/SEV2/SEV3\n- Duration: X hours X minutes\n- Services affected:\n\n## What happened\n- Timeline of events\n- When was it detected\n- How was it resolved\n\n## Root Cause\n- Not who, but what and why\n\n## Action Items\n- [ ] Prevent recurrence\n- [ ] Improve detection\n- [ ] Improve mitigation\n\n## Lessons Learned\n- What went well\n- What went wrong\n- What to improve\n\n## Blameless Statement\nThis was a system/process failure, not a people failure.","description":"Blameless postmortem template focusing on system causes, not individual blame."},{"title":"Team Working Agreement","useCase":"DevOps culture contract.","code":"# DevOps Team Working Agreement\n\n1. We deploy to production daily\n2. We own our code end-to-end\n3. We automate everything we can\n4. We share on-call rotation\n5. We review code before merging\n6. We write tests for every change\n7. We monitor what we deploy\n8. We respond to alerts within 5 min\n9. We run blameless postmortems\n10. We improve something every sprint","description":"Team working agreement codifying DevOps cultural principles into daily practices."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the focus of blameless postmortems?","options":["Who caused the failure","What system/process failed","Which team to blame","How to punish mistakes"],"answer":1,"explanation":"Blameless postmortems focus on system and process failures, not individuals."},{"question":"What does \"you build it, you run it\" mean?","options":["Developers only build","Developers own code in production","Operations runs everything","Only senior devs handle production"],"answer":1,"explanation":"Developers are responsible for their code from development through production, including on-call."},{"question":"What is the foundation of high-performing DevOps teams?","options":["Expensive tools","Psychological safety","More managers","Longer release cycles"],"answer":1,"explanation":"Psychological safety — team members feel safe to take risks and admit mistakes — is the foundation of high performance."},{"question":"DevOps Culture — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"DevOps Culture — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"DevOps Culture — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"DevOps Culture — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"DevOps Culture — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"DevOps Culture — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"DevOps Culture — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-agile-vs-devops"] = {"id":"devops-agile-vs-devops","title":"Agile vs DevOps","difficulty":"beginner","estimatedMinutes":15,"tldr":["Agile is a software development methodology focused on iterative development, customer collaboration, and responding to change.","DevOps extends Agile by bridging the gap between development and operations, focusing on the entire delivery pipeline.","Agile answers \"how do we build software better?\" while DevOps answers \"how do we deliver and operate it better?\"","They are complementary: Agile improves development processes, DevOps extends that to deployment and operations."],"laymanDefinition":"Agile is like improving how a kitchen prepares meals — better recipes, faster chopping, tastier dishes. DevOps is like connecting that kitchen to the dining room with a conveyor belt — meals go from chef to customer instantly, and empty plates come back with feedback notes.","deepDive":[{"heading":"Agile Principles (Agile Manifesto)","text":"Individuals and interactions over processes and tools. Working software over comprehensive documentation. Customer collaboration over contract negotiation. Responding to change over following a plan. Twelve principles including: deliver frequently, welcome changing requirements, business and dev work together daily."},{"heading":"DevOps Extensions to Agile","text":"Agile stops at \"working software\" delivered to operations. DevOps continues: deploy to production, monitor, operate, gather feedback, improve. DevOps adds: infrastructure as code, automated deployment, production monitoring, incident response, reliability engineering."},{"heading":"Key Differences","text":"Agile scope: dev team focused (sprints, standups, retrospectives). DevOps scope: entire value stream (code to production to feedback). Agile metric: velocity. DevOps metric: deployment frequency, MTTR. Agile practices: Scrum, Kanban. DevOps practices: CI/CD, IaC, monitoring."},{"heading":"How They Work Together","text":"Agile teams plan and build in sprints. DevOps automates the path from commit to production. Agile retrospectives feed into DevOps improvements. DevOps monitoring feeds back into Agile backlog. Combined: faster iterations with reliable deliveries. Best practice: DevOps-enabled Agile teams."}],"interviewAnswer":"Agile and DevOps are complementary, not competing. Agile improves how you build; DevOps improves how you deliver and operate. Agile focuses on development teams; DevOps spans the entire organization. Agile without DevOps is slow delivery; DevOps without Agile is automation without direction.","interviewQuestions":[{"question":"What is Agile?","answer":"A software development methodology focused on iterative development, customer collaboration, and responding to change."},{"question":"What does DevOps add beyond Agile?","answer":"Operations, deployment automation, production monitoring, incident response, and reliability engineering."},{"question":"What is the Agile Manifesto?","answer":"Four values: individuals/interactions, working software, customer collaboration, responding to change."},{"question":"What is a key difference between Agile and DevOps scope?","answer":"Agile focuses on dev team; DevOps spans the entire value stream from code to production."},{"question":"What does Agile measure?","answer":"Velocity (story points per sprint). DevOps measures deployment frequency, lead time, MTTR, change failure rate."},{"question":"Can you do DevOps without Agile?","answer":"Partially. But Agile provides the iterative development rhythm that DevOps automates and accelerates."},{"question":"Agile vs DevOps — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Agile vs DevOps — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Agile vs DevOps — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Agile vs DevOps — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Agile vs DevOps</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Agile</text><text x=\"65\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Build software bette</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">r</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Scrum/Kanban</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Iterative dev</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Velocity</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Sprint metrics</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"115\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"217.5\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DevOps</text><text x=\"217.5\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Deliver + operate be</text><text x=\"217.5\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">tter</text><rect x=\"160\" y=\"65\" width=\"115\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"217.5\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI/CD</text><text x=\"217.5\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automate pipeline</text><rect x=\"160\" y=\"95\" width=\"115\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"217.5\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DORA Metrics</text><text x=\"217.5\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Deploy freq, MTTR</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"100\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Agile + DevOps</text><text x=\"385\" y=\"107\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Complementary: Agile builds, DevOp</text><text x=\"385\" y=\"118\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">s delivers and operates. Together:</text><text x=\"385\" y=\"129\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> fast + reliable.</text><text x=\"240\" y=\"180\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Agile vs DevOps: Agile improves development; DevOp</text><text x=\"240\" y=\"192\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">s extends to delivery and operations. Both needed.</text></svg>","codeExamples":[{"title":"Agile Sprint with DevOps Pipeline","useCase":"Combined workflow.","code":"# Agile + DevOps combined workflow\n\n# Sprint Planning (Agile)\n# → Backlog refinement, story pointing\n\n# Daily Development (Agile + DevOps)\n# → Code → Commit → CI build → Test → Deploy to staging\n\n# Sprint Review (Agile)\n# → Demo working software\n\n# Release (DevOps)\n# → Approve → Deploy to production via pipeline\n\n# Monitor (DevOps)\n# → Track metrics, errors, user behavior\n\n# Retrospective (Agile + DevOps)\n# → What improved? What broke? What to change next sprint?\n\n# Feedback Loop\n# → Production data → Backlog → Next sprint","description":"Combined Agile Sprint with DevOps pipeline showing how both methodologies work together."},{"title":"Agile vs DevOps Comparison","useCase":"Side-by-side differences.","code":"+-------------------+-------------------+-------------------+\n| Aspect           | Agile             | DevOps            |\n+-------------------+-------------------+-------------------+\n| Focus            | Development       | Full lifecycle    |\n| Team scope       | Dev team          | Dev + Ops + QA    |\n| Primary metric   | Velocity          | Deploy frequency  |\n| Time horizon     | Sprints (2 wks)   | Continuous        |\n| Key practice     | Standups          | Monitoring        |\n| Output           | Working software  | Running software  |\n| Automation       | Optional          | Essential         |\n| Infrastructure   | Dev environment   | Full IaC          |\n+-------------------+-------------------+-------------------+","description":"Side-by-side comparison of Agile and DevOps across key dimensions."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What does Agile focus on?","options":["Operations","Development process","Deployment","Monitoring"],"answer":1,"explanation":"Agile focuses on improving the software development process."},{"question":"What does DevOps add beyond Agile?","options":["Better documentation","Operations and delivery pipeline","Longer sprints","More meetings"],"answer":1,"explanation":"DevOps extends Agile by adding operations, deployment automation, monitoring, and incident response."},{"question":"What is a key DevOps metric NOT used in Agile?","options":["Velocity","Story points","Deployment frequency","Sprint burndown"],"answer":2,"explanation":"Deployment frequency is a DORA metric specific to DevOps, not typically tracked in Agile alone."},{"question":"Agile vs DevOps — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Agile vs DevOps — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Agile vs DevOps — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Agile vs DevOps — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Agile vs DevOps — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Agile vs DevOps — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Agile vs DevOps — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-sdlc"] = {"id":"devops-sdlc","title":"SDLC (Software Development Lifecycle)","difficulty":"beginner","estimatedMinutes":15,"tldr":["SDLC is the process of planning, creating, testing, and deploying software. It defines the stages software goes through from concept to retirement.","Traditional SDLC models: Waterfall (linear), V-Model, Spiral, Iterative. Modern: Agile, DevOps-enabled SDLC.","SDLC phases: Requirements → Design → Implementation → Testing → Deployment → Maintenance.","DevOps transforms SDLC by making it continuous (not linear), automated (not manual), and feedback-driven at every stage."],"laymanDefinition":"SDLC is like the blueprint for building a house. First you plan (requirements), then you draw (design), then you build (implementation), then you inspect (testing), then you move in (deployment), and you maintain it forever (maintenance). DevOps makes this house-building continuous — like adding rooms while living in it.","deepDive":[{"heading":"Waterfall Model","text":"Sequential: each phase completes before next starts. Requirements → Design → Implementation → Testing → Deployment → Maintenance. No going back. Good for: regulated industries, clear requirements, small projects. Bad for: changing requirements, complex projects. Rarely used alone today."},{"heading":"Agile/DevOps SDLC","text":"Continuous loop, not linear. Requirements evolve throughout. Design is incremental. Implementation is iterative. Testing is automated and continuous. Deployment is frequent (daily). Maintenance is proactive (monitoring). Feedback feeds back into requirements. This is the modern approach."},{"heading":"DevOps-Enabled SDLC Benefits","text":"Faster time to market: from months to hours. Higher quality: automated testing catches issues early. Lower risk: small, frequent deployments. Better feedback: monitoring data informs improvements. Lower costs: automation reduces manual effort. Happier teams: less firefighting, more innovation."},{"heading":"SDLC Phases in DevOps Context","text":"Requirements: user stories, acceptance criteria, compliance needs. Design: architecture reviews, security review, capacity planning. Implementation: Git, pair programming, code reviews. Testing: CI pipeline, unit, integration, e2e, security, performance. Deployment: automated pipeline, blue-green, canary. Maintenance: monitoring, incident response, updates."}],"interviewAnswer":"SDLC is the process framework for building software. Traditional models (Waterfall) are linear. Modern DevOps-enabled SDLC is continuous, automated, and feedback-driven. Understanding SDLC helps you see where DevOps practices apply at each stage.","interviewQuestions":[{"question":"What is SDLC?","answer":"Software Development Lifecycle — the process of planning, creating, testing, and deploying software from concept to retirement."},{"question":"What are the traditional SDLC phases?","answer":"Requirements → Design → Implementation → Testing → Deployment → Maintenance."},{"question":"What is the Waterfall model?","answer":"A linear SDLC where each phase must complete before the next begins. No going back to previous phases."},{"question":"How does DevOps change SDLC?","answer":"Makes it continuous (not linear), automated (not manual), and feedback-driven at every stage."},{"question":"What is the Agile/DevOps SDLC?","answer":"A continuous loop where requirements evolve, development is iterative, testing is automated, and deployment is frequent."},{"question":"What are the benefits of DevOps-enabled SDLC?","answer":"Faster delivery, higher quality, lower risk, better feedback, lower costs, happier teams."},{"question":"SDLC (Software Development Lifecycle) — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"SDLC (Software Development Lifecycle) — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"SDLC (Software Development Lifecycle) — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"SDLC (Software Development Lifecycle) — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">SDLC (Software Development Lifecycle)</text><rect x=\"10\" y=\"35\" width=\"85\" height=\"18\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"52.5\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Requirements</text><text x=\"52.5\" y=\"47\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">What to build</text><line x1=\"95\" y1=\"44\" x2=\"100\" y2=\"44\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"110\" y=\"35\" width=\"75\" height=\"18\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"147.5\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Design</text><text x=\"147.5\" y=\"47\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">How to build</text><line x1=\"185\" y1=\"44\" x2=\"190\" y2=\"44\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"200\" y=\"35\" width=\"95\" height=\"18\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"247.5\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Implementation</text><text x=\"247.5\" y=\"47\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Write code</text><line x1=\"295\" y1=\"44\" x2=\"300\" y2=\"44\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"310\" y=\"35\" width=\"70\" height=\"18\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"345\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Testing</text><text x=\"345\" y=\"36\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Verify quali</text><text x=\"345\" y=\"47\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ty</text><line x1=\"380\" y1=\"44\" x2=\"385\" y2=\"44\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"58\" width=\"85\" height=\"18\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"52.5\" y=\"74\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deployment</text><text x=\"52.5\" y=\"70\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Release to prod</text><line x1=\"95\" y1=\"67\" x2=\"100\" y2=\"67\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"110\" y=\"58\" width=\"85\" height=\"18\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"152.5\" y=\"74\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Maintenance</text><text x=\"152.5\" y=\"70\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Monitor + fix</text><line x1=\"195\" y1=\"67\" x2=\"10\" y2=\"44\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"85\" width=\"300\" height=\"20\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"160\" y=\"100\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DevOps: Continuous. Automated. Feedback-driven.</text><rect x=\"10\" y=\"115\" width=\"400\" height=\"30\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"210\" y=\"131\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SDLC + DevOps</text><text x=\"210\" y=\"128\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Traditional SDLC is linear. DevOps makes it an automated, continuous, fe</text><text x=\"210\" y=\"139\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">edback-driven loop.</text><text x=\"240\" y=\"180\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">SDLC: Software Development Lifecycle. DevOps trans</text><text x=\"240\" y=\"192\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">forms it from linear to continuous.</text></svg>","codeExamples":[{"title":"SDLC Phases with DevOps Automation","useCase":"Automation at each phase.","code":"# SDLC Phase → DevOps Automation\n\n# Requirements → Jira/Notion (tracking)\n#   Auto-linking commits to tickets\n\n# Design → Architecture Decision Records (ADR)\n#   Auto-review with linters\n\n# Implementation → Git Hooks, pre-commit\n#   Auto-format, auto-lint on commit\n\n# Testing → CI Pipeline\n#   Auto-run tests on every PR\n\n# Deployment → CD Pipeline\n#   Auto-deploy on merge to main\n\n# Maintenance → Monitoring + Alerting\n#   Auto-alert on error thresholds","description":"Mapping DevOps automation to each phase of the SDLC."},{"title":"SDLC Model Comparison","useCase":"Waterfall vs Agile vs DevOps.","code":"+-------------------+-------------------+-------------------+\n| Aspect           | Waterfall         | Agile             |\n| DevOps SDLC      |                   |                   |\n+-------------------+-------------------+-------------------+\n| Approach         | Linear sequential | Iterative         |\n| Continuous loop  |                   |                   |\n| Change tolerance | Low (late=bad)    | High (welcome)    |\n| Very high        |                   |                   |\n| Delivery         | One big release   | Multiple releases |\n| Continuous       |                   |                   |\n| Testing          | End of cycle      | Every iteration   |\n| Automated always |                   |                   |\n| Feedback         | Post-release      | Sprint reviews    |\n| Real-time monitor |                   |                   |\n| Risk             | High (all at end) | Lower (frequent)  |\n| Lowest (automated)|                   |                   |\n+-------------------+-------------------+-------------------+","description":"Comparison of Waterfall, Agile, and DevOps SDLC models showing progression toward continuous delivery."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What are the traditional SDLC phases?","options":["Plan, Do, Check, Act","Requirements, Design, Implementation, Testing, Deployment, Maintenance","Code, Build, Test, Deploy","Dev, Ops, QA, Security"],"answer":1,"explanation":"Traditional SDLC phases are Requirements → Design → Implementation → Testing → Deployment → Maintenance."},{"question":"How does DevOps change SDLC?","options":["More documentation","Continuous and automated instead of linear and manual","Fewer phases","Slower process"],"answer":1,"explanation":"DevOps transforms SDLC into a continuous, automated, feedback-driven process."},{"question":"What is the Waterfall model?","options":["Iterative development","Sequential phases without going back","Continuous delivery","Agile framework"],"answer":1,"explanation":"Waterfall is a linear sequential model where each phase completes before the next begins."},{"question":"SDLC (Software Development Lifecycle) — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"SDLC (Software Development Lifecycle) — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"SDLC (Software Development Lifecycle) — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"SDLC (Software Development Lifecycle) — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"SDLC (Software Development Lifecycle) — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"SDLC (Software Development Lifecycle) — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"SDLC (Software Development Lifecycle) — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-ci"] = {"id":"devops-ci","title":"Continuous Integration","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Continuous Integration (CI) is the practice of merging all developer working copies to a shared mainline several times a day.","Each merge triggers an automated build and test run to detect integration errors as early as possible.","CI principle: \"if it hurts, do it more often\" — frequent merging reduces integration pain.","Key CI practices: maintain a single source repository, automate builds, make builds self-testing, keep builds fast, commit to mainline daily."],"laymanDefinition":"CI is like a group of cooks each preparing ingredients (code) at their own stations. Instead of combining everything at the end (and finding out the sauces are incompatible), they mix ingredients into a shared pot every few minutes and taste-test immediately. If something is wrong, only the last addition needs fixing.","deepDive":[{"heading":"CI Pipeline Stages","text":"Trigger: code push to repository (any branch). Stage 1 - Checkout: get latest code. Stage 2 - Install: resolve dependencies (npm install, mvn dependency:resolve). Stage 3 - Build: compile code, package artifacts. Stage 4 - Test: unit tests, integration tests, linting, code coverage. Stage 5 - Report: test results, coverage reports, quality gates."},{"heading":"CI Best Practices","text":"Commit frequently (several times daily). Keep commits small and focused. Write tests before or with code. Fix broken builds immediately — no one commits on a red build. Use feature flags instead of branches. Run CI on every branch push. Keep build under 10 minutes. Use fast feedback mechanisms (Slack, email)."},{"heading":"CI vs CD vs CD","text":"CI (Continuous Integration): merge and test frequently. CD (Continuous Delivery): CI + automated deployment to staging, manual approval for production. CD (Continuous Deployment): CI + automated deployment all the way to production with no manual gates. CI is prerequisite for both delivery and deployment."},{"heading":"CI Tools and Services","text":"GitHub Actions, GitLab CI/CD, Jenkins, CircleCI, Travis CI, Bitbucket Pipelines, Azure DevOps, AWS CodePipeline. Key features: webhook triggers, parallel jobs, matrix builds, artifact storage, test reporting, cache management, secret handling."}],"interviewAnswer":"CI is the foundation of all DevOps practices. Merge frequently, build automatically, test every change, fix broken builds immediately. Keep builds fast. CI catches integration issues early when they are cheap to fix. Without CI, all other DevOps practices are built on an unstable foundation.","interviewQuestions":[{"question":"What is Continuous Integration?","answer":"Merging code changes frequently (multiple times daily) with automated build and test on each merge."},{"question":"What is the main goal of CI?","answer":"Detect integration errors early and fix them quickly when they are cheap to resolve."},{"question":"What happens when a CI build fails?","answer":"The team stops other work and fixes it immediately. Never commit on a broken build."},{"question":"What is the difference between CI and CD?","answer":"CI = frequent merge + build + test. CD = CI + automated deployment readiness."},{"question":"What makes a good CI pipeline?","answer":"Fast (< 10 min), reliable, self-testing, clear reporting, triggers on every push."},{"question":"What are common CI tools?","answer":"GitHub Actions, Jenkins, GitLab CI, CircleCI, Travis CI, Azure DevOps."},{"question":"Continuous Integration — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Continuous Integration — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Continuous Integration — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Continuous Integration — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Continuous Integration</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Developer A</text><text x=\"60\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Commits code</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Developer B</text><text x=\"60\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Commits code</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Developer C</text><text x=\"60\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Commits code</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"85\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI Server</text><text x=\"200\" y=\"92\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto-build + auto-</text><text x=\"200\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">test on every merg</text><text x=\"200\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">e</text><rect x=\"270\" y=\"35\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"320\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build</text><text x=\"320\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Compile + package</text><rect x=\"270\" y=\"65\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"320\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Test</text><text x=\"320\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Unit + integration</text><rect x=\"270\" y=\"95\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"320\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Report</text><text x=\"320\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Results + artifact</text><text x=\"320\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">s</text><line x1=\"250\" y1=\"48\" x2=\"270\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"78\" x2=\"270\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"108\" x2=\"270\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"390\" y=\"35\" width=\"90\" height=\"85\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"435\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Main Branch</text><text x=\"435\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Always working, </text><text x=\"435\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">always green</text><line x1=\"370\" y1=\"48\" x2=\"390\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"370\" y1=\"78\" x2=\"390\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"370\" y1=\"108\" x2=\"390\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><text x=\"240\" y=\"175\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CI: Merge frequently + build + test automatically.</text><text x=\"240\" y=\"187\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> Catch integration errors early.</text></svg>","codeExamples":[{"title":"Basic CI Pipeline (GitHub Actions)","useCase":"CI on every push.","code":"name: CI Pipeline\non:\n  push:\n    branches: [main, develop]\n  pull_request:\n    branches: [main]\n\njobs:\n  build-and-test:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - uses: actions/setup-node@v3\n        with:\n          node-version: 18\n      - run: npm ci\n      - run: npm run lint\n      - run: npm test -- --coverage\n      - run: npm run build\n      - uses: actions/upload-artifact@v3\n        with:\n          name: build-output\n          path: dist/","description":"Basic CI pipeline that runs lint, tests, and build on every push and PR."},{"title":"Jenkins CI Pipeline (Jenkinsfile)","useCase":"Declarative CI pipeline.","code":"pipeline {\n  agent any\n\n  stages {\n    stage('Checkout') {\n      steps { checkout scm }\n    }\n    stage('Install') {\n      steps { sh 'npm ci' }\n    }\n    stage('Lint') {\n      steps { sh 'npm run lint' }\n    }\n    stage('Test') {\n      steps {\n        sh 'npm test'\n        junit 'reports/*.xml'\n      }\n    }\n    stage('Build') {\n      steps { sh 'npm run build' }\n    }\n  }\n  post {\n    success {\n      archiveArtifacts 'dist/**'\n    }\n  }\n}","description":"Jenkins declarative pipeline for CI with checkout, install, lint, test, and build stages."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the main goal of CI?","options":["Deploy faster","Catch integration errors early","Automate everything","Reduce costs"],"answer":1,"explanation":"CI catches integration errors early when they are cheap and easy to fix."},{"question":"How often should developers commit with CI?","options":["Once per week","Several times daily","Only when feature is complete","Once per sprint"],"answer":1,"explanation":"CI practices recommend committing to mainline several times each day."},{"question":"What happens when a CI build breaks?","options":["Wait for next release","Fix it immediately before other work","Revert all changes","Ignore it"],"answer":1,"explanation":"Broken CI builds should be fixed immediately. Never commit code on a broken build."},{"question":"Continuous Integration — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Continuous Integration — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Continuous Integration — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Continuous Integration — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Continuous Integration — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Continuous Integration — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Continuous Integration — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-cd"] = {"id":"devops-cd","title":"Continuous Delivery","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Continuous Delivery (CD) is the practice of keeping your codebase deployable at any moment by automating the release process.","CD extends CI: after CI builds and tests pass, CD automates deployment to staging environments and prepares the release.","Key difference from Continuous Deployment: CD requires manual approval for production deployment; Continuous Deployment goes all the way automatically.","CD ensures every change that passes CI is potentially releasable — the release decision is a business choice, not a technical hurdle."],"laymanDefinition":"Continuous Delivery is like having a car that is always washed, fueled, and ready to drive. The car (code) is prepared automatically after every checkup (CI). But the actual trip (deployment to production) requires a human to say \"let's go.\" The car is always ready — you just need to decide when to leave.","deepDive":[{"heading":"CD Pipeline Stages after CI","text":"CI completes → Artifact stored in repository (Nexus, Artifactory, Docker Hub). Deploy to staging: automated, full environment. Integration tests: automated against staging. Performance tests: load testing, stress testing. Security scan: SAST, DAST, dependency scanning. Release approval: manual or automatic gating. Deploy to production: automated deploy with guardrails."},{"heading":"Release Automation","text":"Versioning: semantic versioning (major.minor.patch). Changelog: auto-generated from commits. Release notes: auto-generated with links to issues/PRs. Tagging: git tag with version. Artifact promotion: move through environments (dev → staging → prod). Deployment: blue-green, canary, or rolling."},{"heading":"CD Best Practices","text":"Automate everything after CI. Keep staging identical to production. Use feature flags to decouple deployment from release. Practice \"dark launches\" — deploy invisible features. Implement smoke tests as deployment verification. Have a rollback plan for every release. Monitor deployment health metrics."},{"heading":"CD Prerequisites","text":"Comprehensive automated test suite. Fast, reliable CI pipeline. Configuration management (environment-specific configs outside code). Database migration automation. Infrastructure as Code. Monitoring and logging in place. Rollback automation. Feature flags for risky changes."}],"interviewAnswer":"Continuous Delivery means your code is always ready to go to production. The CI pipeline proves it works; CD makes it available. A person decides when to press \"go.\" This decouples the technical readiness from the business decision to release.","interviewQuestions":[{"question":"What is Continuous Delivery?","answer":"The practice of keeping codebase always deployable by automating the release process up to production deployment."},{"question":"What is the difference between Continuous Delivery and Continuous Deployment?","answer":"CD requires manual approval for production deploy. Continuous Deployment is fully automated through production."},{"question":"What happens after CI in a CD pipeline?","answer":"Artifact stored, deployed to staging, integration tests run, security scanned, release prepared for approval."},{"question":"What is a deployment approval gate?","answer":"A manual or automated check that must pass before deploying to production. Common in CD (not Continuous Deployment)."},{"question":"What is artifact promotion?","answer":"Moving a verified artifact through environments: dev → staging → production, promoting only after passing each stage."},{"question":"What tools support CD pipelines?","answer":"Spinnaker, ArgoCD, Jenkins, GitLab CI/CD, GitHub Actions, GoCD, Harness."},{"question":"Continuous Delivery — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Continuous Delivery — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Continuous Delivery — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Continuous Delivery — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Continuous Delivery</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI Complete</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Build + test pass</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Artifact Store</text><text x=\"215\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Nexus / Docker Hub</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy Staging</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated deploy</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Integration Tests</text><text x=\"215\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">+ Security + Perf</text><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Release Approval</text><text x=\"65\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Manual gate</text><line x1=\"120\" y1=\"118\" x2=\"150\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"105\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"215\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy Prod</text><text x=\"215\" y=\"113\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated + guardrai</text><text x=\"215\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ls</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"130\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Continuous Delivery</text><text x=\"385\" y=\"137\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Always deployable. CI → staging → </text><text x=\"385\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">approval → production. Human decid</text><text x=\"385\" y=\"159\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">es when to release.</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Continuous Delivery: Keep code always deployable. </text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CI automates quality; CD automates readiness. Huma</text><text x=\"240\" y=\"224\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">n approves release.</text></svg>","codeExamples":[{"title":"CD Pipeline with Manual Approval (GitHub Actions)","useCase":"Deploy with environment approval.","code":"name: Continuous Delivery\non:\n  push:\n    branches: [main]\n\njobs:\n  ci:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - run: npm ci && npm test && npm run build\n      - uses: actions/upload-artifact@v3\n        with:\n          name: build\n          path: dist/\n\n  deploy-staging:\n    needs: ci\n    runs-on: ubuntu-latest\n    environment: staging\n    steps:\n      - run: ./deploy-staging.sh\n\n  deploy-production:\n    needs: deploy-staging\n    runs-on: ubuntu-latest\n    environment: production\n    # Requires manual approval (GitHub Environments)\n    steps:\n      - run: ./deploy-production.sh","description":"CD pipeline with CI, staging deploy, and production deploy requiring manual approval via GitHub Environments."},{"title":"Release Readiness Checklist","useCase":"Automated checks before release.","code":"# Release Readiness Checklist (automated)\n\n# [auto] All CI tests pass?\n# [auto] Code coverage >= 80%?\n# [auto] Security scan passed?\n# [auto] No critical vulnerabilities?\n# [auto] Integration tests pass on staging?\n# [auto] Performance tests within limits?\n# [manual] Product owner approved?\n# [manual] Release notes reviewed?\n# [auto] Database migrations ready?\n# [auto] Rollback plan exists?\n# [auto] Feature flags configured?\n\n# All checks must pass for deployment","description":"Automated and manual checks as release readiness gates in a CD pipeline."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the key difference between CD and Continuous Deployment?","options":["CD is faster","CD requires manual approval for production","CD has no testing","CD is only for staging"],"answer":1,"explanation":"Continuous Delivery has a manual approval gate for production; Continuous Deployment is fully automated."},{"question":"What is artifact promotion?","options":["Deleting old artifacts","Moving artifacts through environments after validation","Creating new artifacts","Versioning artifacts"],"answer":1,"explanation":"Artifact promotion moves verified builds through dev → staging → production environments."},{"question":"What is a prerequisite for CD?","options":["No tests needed","Comprehensive automated test suite","Manual deployment only","Weekly releases"],"answer":1,"explanation":"A comprehensive automated test suite is essential for CD to ensure every build is releasable."},{"question":"Continuous Delivery — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Continuous Delivery — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Continuous Delivery — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Continuous Delivery — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Continuous Delivery — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Continuous Delivery — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Continuous Delivery — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-continuous-deployment"] = {"id":"devops-continuous-deployment","title":"Continuous Deployment","difficulty":"advanced","estimatedMinutes":20,"tldr":["Continuous Deployment is the practice of automatically deploying every change that passes the CI/CD pipeline to production without manual intervention.","Every commit that passes all automated tests, security scans, and quality gates is automatically released to users.","This requires extreme confidence in the automated pipeline: tests, monitoring, rollback, and feature flags must be rock-solid.","Continuous Deployment is the most advanced stage of CI/CD maturity — achieved only by organizations with mature DevOps practices."],"laymanDefinition":"Continuous Deployment is like a self-driving car that takes itself to the garage for maintenance automatically. The mechanic (automated pipeline) checks everything, fixes issues, and puts the car back on the road — all without anyone making a phone call. You just wake up to a better car every morning.","deepDive":[{"heading":"Continuous Deployment Pipeline","text":"Commit → CI (build + test) → Security scan → Deploy to staging → Integration tests → Deploy to production → Smoke tests → Monitor. NO manual approval. Entire process in minutes. Every step has automated rollback if checks fail. Feature flags control feature exposure, not deployment."},{"heading":"Safety Mechanisms for Continuous Deployment","text":"Feature flags: deploy invisible code, enable for users gradually. Canary releases: deploy to 1% of users, gradually increase. Automated rollback: revert if error rate spikes. Deployment freeze: block deploys during sensitive periods. Ring deployment: deploy to internal users → beta → 1% → 10% → 100%. Circuit breakers: stop deployment if metrics go red."},{"heading":"Prerequisites for Continuous Deployment","text":"Comprehensive test suite (unit, integration, e2e, security, performance). Mature monitoring and alerting. Automated rollback capability. Feature flag infrastructure. Blameless culture for deployment failures. Small, frequent commits. Staging/prod parity. Database change automation. Zero-downtime deployment strategy."},{"heading":"Companies Using Continuous Deployment","text":"Netflix: thousands of deployments daily via Spinnaker. Amazon: deploys every 11.7 seconds on average. Etsy: 50+ deployments per day. Facebook: multiple daily deploys. Google: trunk-based development with automated deployment. These companies invest heavily in testing, monitoring, and rollback automation."}],"interviewAnswer":"Continuous Deployment is the pinnacle of automation — every commit that passes your pipeline goes to production automatically. It requires extreme confidence in your testing, monitoring, and rollback capabilities. Feature flags decouple deployment from release. Start with CD for low-risk services, expand gradually.","interviewQuestions":[{"question":"What is Continuous Deployment?","answer":"Every change that passes the automated pipeline is deployed to production without manual intervention."},{"question":"How is Continuous Deployment different from Continuous Delivery?","answer":"Continuous Deployment has no manual approval gate. CD goes to prod automatically. Delivery requires human approval."},{"question":"What safety mechanisms are needed for Continuous Deployment?","answer":"Feature flags, canary releases, automated rollback, ring deployment, circuit breakers, deployment freezes."},{"question":"What is a prerequisite for Continuous Deployment?","answer":"Comprehensive tests, mature monitoring, automated rollback, feature flags, blameless culture, small frequent commits."},{"question":"What companies practice Continuous Deployment?","answer":"Netflix, Amazon, Etsy, Facebook, Google. They deploy many times daily with confidence."},{"question":"How do you start with Continuous Deployment?","answer":"Start with low-risk services, implement feature flags, build automated rollback, monitor everything, expand gradually."},{"question":"Continuous Deployment — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Continuous Deployment — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Continuous Deployment — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Continuous Deployment — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Continuous Deployment</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Commit</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Code pushed</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI</text><text x=\"215\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto build + test</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Security Scan</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto pass/fail</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Staging Tests</text><text x=\"215\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Integration + perf</text><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Production</text><text x=\"65\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto deploy</text><rect x=\"10\" y=\"135\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"151\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Smoke Tests</text><text x=\"65\" y=\"154\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Verify + monitor</text><line x1=\"120\" y1=\"118\" x2=\"150\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"148\" x2=\"150\" y2=\"148\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"290\" y=\"35\" width=\"190\" height=\"130\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Continuous Deployment</text><text x=\"385\" y=\"137\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">No manual gates. Every commit → pr</text><text x=\"385\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">oduction automatically. Requires e</text><text x=\"385\" y=\"159\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">xtreme pipeline confidence.</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Continuous Deployment: Fully automated from commit</text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> to production. Maximum velocity, maximum trust in</text><text x=\"240\" y=\"224\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> pipeline.</text></svg>","codeExamples":[{"title":"Continuous Deployment Flow","useCase":"Fully automated pipeline.","code":"# Continuous Deployment: No manual approval\n\nname: Continuous Deployment\non:\n  push:\n    branches: [main]\n\njobs:\n  test-and-build:\n    runs-on: ubuntu-latest\n    steps:\n      - run: npm ci && npm test && npm run build\n\n  deploy-canary:\n    needs: test-and-build\n    runs-on: ubuntu-latest\n    steps:\n      - run: ./deploy-canary.sh # 1% traffic\n      - run: ./smoke-test.sh\n      - run: ./monitor-metrics.sh\n\n  deploy-full:\n    needs: deploy-canary\n    # Auto-promotes if canary healthy\n    steps:\n      - run: ./deploy-full.sh # 100% traffic\n\n  post-deploy:\n    needs: deploy-full\n    steps:\n      - run: ./run-smoke-tests.sh\n      - run: ./notify-team.sh","description":"Continuous Deployment pipeline with canary, auto-promotion, and post-deploy verification — no manual gates."},{"title":"Simple Deploy Script with Rollback","useCase":"Safeguard for auto-deploy.","code":"#!/bin/bash\n# deploy-with-rollback.sh\n\nAPP=\"my-service\"\nVERSION=$1\nROLLBACK_VERSION=$(cat previous-version.txt)\n\necho \"Deploying $APP version $VERSION...\"\n\n# Deploy new version\nkubectl set image deployment/$APP $APP=$APP:$VERSION\n\n# Wait for rollout\nkubectl rollout status deployment/$APP --timeout=5m\n\n# Check health endpoint\nif curl -f http://myapp.com/health; then\n  echo \"Deploy successful!\"\n  echo $VERSION > previous-version.txt\nelse\n  echo \"Health check failed! Rolling back...\"\n  kubectl rollout undo deployment/$APP\n  exit 1\nfi","description":"Automated deployment script with health check and automatic rollback on failure."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the key difference between Continuous Deployment and Continuous Delivery?","options":["Deployment frequency","Manual approval gate","Test coverage","Build speed"],"answer":1,"explanation":"Continuous Deployment has no manual approval gate — every passing change goes to production automatically."},{"question":"What is essential for safe Continuous Deployment?","options":["Long release cycles","Feature flags + automated rollback","Manual testing","Weekly deployments"],"answer":1,"explanation":"Feature flags and automated rollback are essential safety mechanisms for Continuous Deployment."},{"question":"What is a ring deployment?","options":["Deploying to all users at once","Gradually expanding deployment from internal to 100% of users","Deploying only on weekends","Manual deployment in phases"],"answer":1,"explanation":"Ring deployment rolls out gradually: internal → beta → 1% → 10% → 100% of users."},{"question":"Continuous Deployment — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Continuous Deployment — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Continuous Deployment — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Continuous Deployment — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Continuous Deployment — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Continuous Deployment — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Continuous Deployment — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-iac"] = {"id":"devops-iac","title":"Infrastructure as Code (IaC)","difficulty":"intermediate","estimatedMinutes":25,"tldr":["Infrastructure as Code (IaC) is the practice of managing and provisioning infrastructure through machine-readable definition files, not manual processes.","IaC brings version control, code review, automated testing, and repeatability to infrastructure management.","Two approaches: declarative (desired state — Terraform, CloudFormation) and imperative (step-by-step — Ansible, Chef, Puppet).","Key benefits: consistency (no configuration drift), speed (minutes vs days), reproducibility (same config = same environment), versioned infrastructure."],"laymanDefinition":"IaC is like having a recipe card for your entire server setup instead of a chef who remembers how they made it last time. Want the exact same setup for staging and production? Use the same recipe. Server crashed at 3 AM? Run the recipe on a new machine. Everything is documented, repeatable, and version-controlled.","deepDive":[{"heading":"Declarative vs Imperative IaC","text":"Declarative (Terraform, CloudFormation, Pulumi): you define the desired end state — \"I want 3 EC2 instances with this config.\" The tool figures out how to get there. Imperative (Ansible, Chef, Puppet, Shell): you define the steps — \"Create instance, install nginx, copy config, restart service.\" Declarative is generally preferred for cloud infrastructure."},{"heading":"IaC Best Practices","text":"Store configs in version control (Git). Use modules/abstractions to avoid duplication. Parameterize environments (dev/staging/prod configs). Never hardcode secrets — use vault/parameter store. Test infrastructure changes in CI. Use state locking to prevent concurrent modifications. Plan before apply (terraform plan)."},{"heading":"Terraform Workflow","text":"Write .tf files → terraform init (download providers) → terraform plan (preview changes) → terraform apply (make changes) → terraform destroy (tear down). Terraform maintains state file tracking real-world resources. Remote state (S3, Terraform Cloud) enables team collaboration."},{"heading":"Configuration Drift","text":"When actual infrastructure differs from defined config. Causes: manual changes, failed deployments, expired resources. Detection: terraform plan shows drift. Drift management: reconcile by updating config or importing existing resources. Periodic \"drift detection\" runs in CI."},{"heading":"Immutable vs Mutable Infrastructure","text":"Mutable: modify existing servers in place (Ansible, Chef). Risk of configuration drift over time. Immutable: never modify running servers — replace them (AMI, containers). Terraform + auto-scaling groups enable immutable infrastructure. Immutable is preferred for reliability and consistency."}],"interviewAnswer":"IaC is essential for DevOps. Use declarative tools (Terraform) for cloud infrastructure. Store everything in Git. Never make manual changes to infrastructure. Use modules. Implement CI/CD for infrastructure changes. Plan before apply. Treat infrastructure with the same rigor as application code.","interviewQuestions":[{"question":"What is Infrastructure as Code?","answer":"Managing and provisioning infrastructure through machine-readable definition files instead of manual processes."},{"question":"What is the difference between declarative and imperative IaC?","answer":"Declarative: define desired state (Terraform). Imperative: define steps (Ansible). Declarative is preferred."},{"question":"What is Terraform?","answer":"A declarative IaC tool by HashiCorp for provisioning cloud infrastructure across providers (AWS, Azure, GCP)."},{"question":"What is configuration drift?","answer":"When actual infrastructure differs from defined configuration files. IaC helps detect and prevent drift."},{"question":"What is immutable infrastructure?","answer":"Never modify servers in place — replace them with new instances from a known image. More reliable than mutable."},{"question":"What is Terraform state?","answer":"A file tracking real-world resources, enabling Terraform to map config to actual infrastructure."},{"question":"Infrastructure as Code (IaC) — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Infrastructure as Code (IaC) — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Infrastructure as Code (IaC) — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Infrastructure as Code (IaC) — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Infrastructure as Code (IaC)</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Define</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">main.tf files</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Version Control</text><text x=\"215\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Git</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI/CD</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Test infra changes</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Provision</text><text x=\"215\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Terraform apply</text><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">State</text><text x=\"65\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Track resources</text><rect x=\"10\" y=\"135\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"151\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Drift Check</text><text x=\"65\" y=\"154\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Plan in CI</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"135\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Infrastructure as Code</text><text x=\"385\" y=\"142\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated, versioned, repeatable i</text><text x=\"385\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">nfrastructure. Declarative configs</text><text x=\"385\" y=\"164\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">. No manual changes.</text><text x=\"240\" y=\"205\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">IaC: Manage infrastructure through code. Versioned</text><text x=\"240\" y=\"217\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">, automated, consistent. Terraform, Ansible, Cloud</text><text x=\"240\" y=\"229\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Formation.</text></svg>","codeExamples":[{"title":"Basic Terraform Configuration","useCase":"AWS EC2 instance.","code":"terraform {\n  required_providers {\n    aws = {\n      source  = \"hashicorp/aws\"\n      version = \"~> 5.0\"\n    }\n  }\n}\n\nprovider \"aws\" {\n  region = \"us-east-1\"\n}\n\nresource \"aws_instance\" \"app_server\" {\n  ami           = \"ami-0c55b159cbfafe1f0\"\n  instance_type = \"t2.micro\"\n\n  tags = {\n    Name = \"MyAppServer\"\n  }\n}","description":"Basic Terraform configuration provisioning an AWS EC2 instance declaratively."},{"title":"Ansible Playbook (Imperative IaC)","useCase":"Configure a web server.","code":"---\n- name: Configure web server\n  hosts: webservers\n  become: yes\n  tasks:\n    - name: Install nginx\n      apt:\n        name: nginx\n        state: present\n    - name: Copy config\n      template:\n        src: nginx.conf.j2\n        dest: /etc/nginx/nginx.conf\n      notify: restart nginx\n    - name: Start nginx\n      service:\n        name: nginx\n        state: started\n        enabled: yes\n  handlers:\n    - name: restart nginx\n      service:\n        name: nginx\n        state: restarted","description":"Ansible playbook imperatively describing steps to configure an nginx web server."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What does IaC stand for?","options":["Infrastructure as Code","Integration as Code","Interface as Code","Infrastructure and Configuration"],"answer":0,"explanation":"IaC = Infrastructure as Code."},{"question":"What is the difference between declarative and imperative IaC?","options":["Worse performance","Declarative = desired state; Imperative = steps to reach state","Declarative = steps; Imperative = desired state","No difference"],"answer":1,"explanation":"Declarative IaC (Terraform) defines the desired state. Imperative IaC (Ansible) defines the steps."},{"question":"What is configuration drift?","options":["Improving configuration","When actual infrastructure differs from defined config","Configuration file changes","Automatic configuration"],"answer":1,"explanation":"Configuration drift is when actual infrastructure state differs from the defined IaC configuration."},{"question":"Infrastructure as Code (IaC) — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Infrastructure as Code (IaC) — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Infrastructure as Code (IaC) — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Infrastructure as Code (IaC) — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Infrastructure as Code (IaC) — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Infrastructure as Code (IaC) — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Infrastructure as Code (IaC) — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-config-mgmt"] = {"id":"devops-config-mgmt","title":"Configuration Management","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Configuration Management is the practice of maintaining systems in a desired, consistent state through automated tools and processes.","It ensures all servers, applications, and services are configured consistently across environments.","Tools: Ansible, Puppet, Chef, SaltStack. Each uses a different model (push vs pull, agent vs agentless).","Key concept: desired state configuration — define what the system should look like; the tool makes it so."],"laymanDefinition":"Configuration management is like having a building superintendent who follows a detailed checklist every day. Instead of checking each room manually, they have an automated system that ensures every room has the right temperature, lights, and locks. If something is wrong, the system fixes it automatically.","deepDive":[{"heading":"Push vs Pull Model","text":"Push (Ansible, Salt SSH): control node pushes config to managed nodes. No agent required on managed nodes. Simpler setup. Better for smaller environments. Pull (Puppet, Chef, Salt Minion): agents on managed nodes periodically pull config from master. Scales better for large environments. Agents report status back."},{"heading":"Idempotency in Configuration Management","text":"Running the same config multiple times produces the same result. Only changes what needs changing. If a package is already installed, skip. If a service is already running, do nothing. This is the core principle of configuration management tools. Makes automation safe to run repeatedly."},{"heading":"Configuration Drift Prevention","text":"Drift: servers in a fleet become different over time due to manual changes, failed updates, or partial deployments. Prevention: run config management periodically (cron, pull interval). Automatically remediate drift. Alert on unreconcilable differences. Use immutable infrastructure where possible."},{"heading":"Ansible (Most Popular)","text":"Agentless: uses SSH/WinRM. Push model. YAML playbooks. Large module library. No central server overhead. Good for: configuration management, application deployment, ad-hoc tasks. Simple learning curve. Idempotent by design. Popular for cloud automation."}],"interviewAnswer":"Configuration management keeps your infrastructure consistent and compliant. Ansible is the most accessible tool (agentless, YAML). Use idempotent configurations. Run CM regularly to prevent drift. Combine with IaC: Terraform provisions, CM configures.","interviewQuestions":[{"question":"What is Configuration Management?","answer":"Maintaining systems in a desired, consistent state through automated tools. Ensuring all servers are configured the same."},{"question":"What is the difference between push and pull CM models?","answer":"Push (Ansible): control node pushes config to servers. Pull (Puppet): agents pull config from master."},{"question":"What does idempotent mean in configuration management?","answer":"Running the same config multiple times produces the same result — only changes what needs changing."},{"question":"What is configuration drift?","answer":"Servers becoming different over time due to manual changes or partial updates. CM prevents and remediates drift."},{"question":"What is the most popular configuration management tool?","answer":"Ansible — agentless, push-based, YAML playbooks, large ecosystem."},{"question":"What is the difference between IaC and CM?","answer":"IaC provisions infrastructure (servers, networks). CM configures software on that infrastructure. Both are needed."},{"question":"Configuration Management — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Configuration Management — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Configuration Management — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Configuration Management — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Configuration Management</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Define</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Desired state YAML</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Push (Ansible)</text><text x=\"215\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Control → nodes via </text><text x=\"215\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">SSH</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pull (Puppet)</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Agents → master</text><rect x=\"10\" y=\"100\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Idempotent</text><text x=\"65\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Safe to repeat</text><rect x=\"10\" y=\"130\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Drift Remediation</text><text x=\"65\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto-fix differences</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"130\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Config Management</text><text x=\"385\" y=\"137\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Consistent, automated server confi</text><text x=\"385\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">guration. Ansible, Puppet, Chef. I</text><text x=\"385\" y=\"159\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">dempotent, drift-free.</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Configuration Management: Maintain consistent serv</text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">er configurations with automated, idempotent tools</text><text x=\"240\" y=\"224\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> like Ansible.</text></svg>","codeExamples":[{"title":"Ansible Playbook: Web Server Setup","useCase":"Idempotent configuration.","code":"---\n- name: Configure web servers\n  hosts: all\n  vars:\n    app_port: 3000\n    log_level: info\n\n  tasks:\n    - name: Ensure nginx is installed\n      apt:\n        name: nginx\n        state: present\n\n    - name: Ensure nginx is running\n      service:\n        name: nginx\n        state: started\n        enabled: yes\n\n    - name: Deploy app config\n      template:\n        src: app.conf.j2\n        dest: /etc/myapp/config.json\n      notify: restart myapp\n\n  handlers:\n    - name: restart myapp\n      systemd:\n        name: myapp\n        state: restarted","description":"Ansible playbook for idempotent web server configuration with templates and handlers."},{"title":"Ansible Ad-hoc Commands","useCase":"Quick configuration tasks.","code":"# Check all servers are reachable\nansible all -i inventory.ini -m ping\n\n# Check disk space on all servers\nansible all -i inventory.ini -m shell -a \"df -h\"\n\n# Ensure a package is installed everywhere\nansible all -i inventory.ini -m apt -a \"name=htop state=present\" -b\n\n# Copy a file to all servers\nansible all -i inventory.ini -m copy -a \"src=/local/file dest=/remote/file\"\n\n# Check nginx status on web servers\nansible webservers -i inventory.ini -m service -a \"name=nginx state=started\"","description":"Ansible ad-hoc commands for quick configuration tasks across server fleets."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What does idempotent mean?","options":["Fast execution","Same result regardless of how many times you run it","Requires root access","Only runs once"],"answer":1,"explanation":"Idempotent means running the same configuration multiple times produces the same result."},{"question":"What is the difference between push and pull CM?","options":["Push is slower","Push sends config from server; pull agents fetch from master","No difference","Push requires agents"],"answer":1,"explanation":"Push model (Ansible) sends config from control node. Pull model (Puppet) has agents fetch from master."},{"question":"Which is the most popular CM tool?","options":["Chef","Puppet","Ansible","SaltStack"],"answer":2,"explanation":"Ansible is the most popular configuration management tool, known for being agentless and easy to learn."},{"question":"Configuration Management — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Configuration Management — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Configuration Management — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Configuration Management — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Configuration Management — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Configuration Management — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Configuration Management — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-immutable-infra"] = {"id":"devops-immutable-infra","title":"Immutable Infrastructure","difficulty":"advanced","estimatedMinutes":20,"tldr":["Immutable infrastructure is a pattern where servers are never modified after deployment. When changes are needed, new servers are built from a common image.","Instead of patching or upgrading running servers (mutable), you replace them entirely with new instances running the updated image.","Benefits: no configuration drift, consistent environments, easy rollback (switch to old image), simplified debugging (known state).","Enabling technologies: container images (Docker), AMIs (AWS machine images), virtual machine snapshots, auto-scaling groups, blue-green deployments."],"laymanDefinition":"Immutable infrastructure is like replacing a lightbulb instead of repairing it. When a bulb burns out (needs a change), you don't fix the filament — you screw in a brand new bulb. Every bulb is identical, factory-made. Your servers are the same: when anything needs to change, you provision a fresh one.","deepDive":[{"heading":"Immutable vs Mutable","text":"Mutable: SSH into server, update config, restart service. Over time, servers become snowflakes (unique, undocumented differences). Immutable: build new image with changes, deploy new instances, terminate old ones. Every instance is identical to the image. No drift. Predictable. Debugging is easier because you know the exact state."},{"heading":"Building Immutable Images","text":"Step 1: Start with base image (OS + security patches). Step 2: Install dependencies and application. Step 3: Configure settings baked into image. Step 4: Create golden image (AMI, Docker image). Step 5: Deploy instances from image. Never SSH into running instances. Never hotfix."},{"heading":"Immutable Infrastructure with Containers","text":"Docker containers are the ultimate expression of immutability. Dockerfile defines exact image contents. Image is built once, deployed everywhere. No differences between dev, staging, production. Registry stores image versions. Rollback is switching to previous image tag. Kubernetes manages immutable container deployments."},{"heading":"Challenges and Solutions","text":"Challenge: stateful services (databases). Solution: externalize state to managed services (RDS), persistent volumes. Challenge: hotfix urgency. Solution: quick image build pipeline, feature flags. Challenge: configuration. Solution: bake config into image or use env vars at deploy time. Challenge: cost. Solution: immutable is often cheaper (no snowflake management)."}],"interviewAnswer":"Immutable infrastructure is a cornerstone of modern DevOps. Treat servers as disposable — never modify them in place. Use Docker images or AMIs. Combine with auto-scaling and blue-green deployments. Externalize state. The result: no drift, easy rollbacks, and perfect consistency.","interviewQuestions":[{"question":"What is immutable infrastructure?","answer":"Servers are never modified after deployment. Changes mean replacing the entire server from a new image."},{"question":"What is the difference between immutable and mutable infrastructure?","answer":"Mutable: modify servers in place. Immutable: replace servers entirely for any change."},{"question":"What are the benefits of immutable infrastructure?","answer":"No configuration drift, consistent environments, easy rollback, simplified debugging."},{"question":"How do containers relate to immutable infrastructure?","answer":"Containers are inherently immutable — the image defines exact contents; any change requires a new image."},{"question":"What is a golden image?","answer":"A master image (AMI, VM snapshot) used as the basis for all instances in immutable infrastructure."},{"question":"How do you handle databases with immutable infrastructure?","answer":"Externalize state to managed services (RDS) or persistent volumes — keep data outside ephemeral compute."},{"question":"Immutable Infrastructure — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Immutable Infrastructure — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Immutable Infrastructure — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Immutable Infrastructure — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Immutable Infrastructure</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build Image</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Golden AMI / Docker</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy</text><text x=\"215\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New instances from i</text><text x=\"215\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">mage</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Running</text><text x=\"65\" y=\"73\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Never SSH, never pat</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ch</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Change Needed</text><text x=\"65\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Build new image vers</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ion</text><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"215\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Replace</text><text x=\"215\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New instances</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Terminate</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Old instances remove</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">d</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"120\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Immutable Infrastructure</text><text x=\"385\" y=\"127\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Never modify servers. Replace with</text><text x=\"385\" y=\"138\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> new images. No drift. Easy rollba</text><text x=\"385\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ck. Containers + AMIs.</text><text x=\"240\" y=\"190\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Immutable Infrastructure: Replace, never modify. B</text><text x=\"240\" y=\"202\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">uild golden images, deploy new instances, terminat</text><text x=\"240\" y=\"214\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">e old ones.</text></svg>","codeExamples":[{"title":"Dockerfile for Immutable App Image","useCase":"Deterministic container build.","code":"# Dockerfile — immutable application image\nFROM node:18-alpine AS base\nWORKDIR /app\nCOPY package*.json ./\nRUN npm ci --only=production\n\nFROM base AS build\nCOPY . .\nRUN npm run build\n\nFROM nginx:alpine AS production\nCOPY --from=build /app/dist /usr/share/nginx/html\nCOPY nginx.conf /etc/nginx/conf.d/default.conf\nEXPOSE 80\nHEALTHCHECK --interval=30s CMD wget -qO- http://localhost/ || exit 1","description":"Multi-stage Dockerfile building an immutable production image — no runtime modifications allowed."},{"title":"Packer: Build Golden AMI","useCase":"Automated machine image creation.","code":"# packer.pkr.hcl — build immutable AMI\npacker {\n  required_plugins {\n    amazon = {\n      version = \">= 1.0.0\"\n      source  = \"github.com/hashicorp/amazon\"\n    }\n  }\n}\n\nsource \"amazon-ebs\" \"webapp\" {\n  ami_name      = \"myapp-{{timestamp}}\")\n  instance_type = \"t2.micro\"\n  region        = \"us-east-1\"\n  source_ami_filter {\n    filters = {\n      name = \"amzn2-ami-hvm-*-x86_64-gp2\"\n    }\n  }\n  communicator = \"ssh\"\n  ssh_username = \"ec2-user\"\n}\n\nbuild {\n  sources = [\"source.amazon-ebs.webapp\"]\n  provisioner \"shell\" {\n    inline = [\n      \"sudo yum update -y\",\n      \"sudo yum install -y nginx\",\n      \"sudo systemctl enable nginx\"\n    ]\n  }\n}","description":"Packer builds immutable AMIs by starting from a base image, provisioning, and creating a golden image."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the key principle of immutable infrastructure?","options":["Servers are patched regularly","Servers are replaced, never modified","Servers are backed up daily","Servers are manually configured"],"answer":1,"explanation":"Immutable infrastructure replaces servers entirely rather than modifying them in place."},{"question":"What is a benefit of immutable infrastructure?","options":["More complex debugging","No configuration drift","Higher costs","Slower deployments"],"answer":1,"explanation":"No configuration drift — every instance is identical to the golden image it was built from."},{"question":"How do containers relate to immutability?","options":["Containers are mutable by default","Container images are immutable — any change requires a new image","Containers cannot be immutable","Only Docker supports immutability"],"answer":1,"explanation":"Container images are inherently immutable. Any change requires building a new image version."},{"question":"Immutable Infrastructure — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Immutable Infrastructure — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Immutable Infrastructure — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Immutable Infrastructure — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Immutable Infrastructure — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Immutable Infrastructure — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Immutable Infrastructure — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-shift-left"] = {"id":"devops-shift-left","title":"Shift Left Testing","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Shift Left Testing is the practice of moving testing activities earlier in the development lifecycle (\"to the left\" on the timeline).","Traditional testing happens at the end (right side). Shift Left moves it to the beginning: requirements, design, and development phases.","Goal: catch defects earlier when they are cheaper and faster to fix. A bug found during development costs 10x less than one found in production.","Includes: static analysis, code reviews, unit tests, security scanning in IDE, contract testing, and test-driven development (TDD)."],"laymanDefinition":"Shift Left is like checking your ingredients before you start cooking, instead of tasting the dish at the end and realizing the milk is sour. You catch problems at the grocery store (requirements phase) rather than at the dinner table (production). Fixing a bad ingredient is much cheaper than fixing a ruined meal.","deepDive":[{"heading":"Traditional vs Shift Left","text":"Traditional: requirements → design → code → test → deploy. Testing is a final gate before release. Defects found late are expensive. Shift Left: test during requirements (acceptance criteria), design (architecture review), coding (unit tests, TDD), and continuously in CI. Every phase includes quality checks."},{"heading":"Shift Left Practices","text":"TDD: write tests before code. Static analysis: linters, SonarQube in IDE. Pre-commit hooks: lint, format, secret scanning before commit. CI: run all tests on every push. Contract testing: verify API contracts early. Security scanning: SAST in pipeline. Performance testing: early and often, not just before release."},{"heading":"Shift Left Security (DevSecOps)","text":"Security is integrated from the start, not bolted on at the end. Practices: threat modeling during design (STRIDE). SAST (Static Application Security Testing) in IDE/CI. Dependency scanning (npm audit, Snyk). Secret scanning (truffleHog). Container scanning (Trivy, Snyk). Policy as code (OPA)."},{"heading":"Benefits and Metrics","text":"Cost of defect: caught in development = $X, caught in production = 10-100X. Time to fix: shorter. Quality: higher. Team morale: better (less firefighting). Metrics: defect escape rate (bugs reaching production), mean time to detect (MTTD), mean time to fix (MTTFix), code coverage trend."}],"interviewAnswer":"Shift Left means testing earlier, testing often, and testing in every phase. Catch defects when they are cheapest to fix. Integrate security from the start. Automate everything possible. The earlier you find a bug, the cheaper it is. Make quality everyone's responsibility, not just QA.","interviewQuestions":[{"question":"What is Shift Left Testing?","answer":"Moving testing activities earlier in the development lifecycle — testing during requirements, design, and coding phases."},{"question":"Why is Shift Left important?","answer":"Defects found earlier are exponentially cheaper to fix. A bug in dev costs 10x less than one in production."},{"question":"What is TDD?","answer":"Test-Driven Development — write failing tests before writing code. Ensures testability and forces good design."},{"question":"What is SAST?","answer":"Static Application Security Testing — analyzing source code for security vulnerabilities without executing it."},{"question":"What is defect escape rate?","answer":"The percentage of defects that reach production. Lower is better. A key Shift Left metric."},{"question":"How does Shift Left relate to DevSecOps?","answer":"Security is integrated from the start (threat modeling, SAST, dependency scanning) rather than being a final gate."},{"question":"Shift Left Testing — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Shift Left Testing — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Shift Left Testing — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Shift Left Testing — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Shift Left Testing</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Requirements</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Acceptance criteria</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Design</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Architecture review</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Development</text><text x=\"65\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">TDD + static analysi</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">s</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI Pipeline</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">All tests every push</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Production</text><text x=\"65\" y=\"163\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Defect escape minimi</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">zed</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SHIFT LEFT</text><text x=\"270\" y=\"162\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Test earlier. Catch defects when they ar</text><text x=\"270\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">e cheap. Quality from the start, not the</text><text x=\"270\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> end.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Shift Left: Move testing earlier in the lifecycle.</text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> Find defects when they are cheapest to fix.</text></svg>","codeExamples":[{"title":"Pre-commit Hook for Shift Left","useCase":"Catch issues before commit.","code":"#!/bin/bash\n# .git/hooks/pre-commit — runs before every commit\n\necho \"Running pre-commit checks...\"\n\n# Lint check\nnpm run lint || exit 1\n\n# Format check\nnpm run format:check || exit 1\n\n# Secret scanning\nnpx truffleHog --regex --entropy=False . || true\n\n# Run unit tests for changed files\nnpm test -- --changedSince=HEAD || exit 1\n\n# Check for TODO/FIXME comments\nif git diff --cached | grep -E \"TODO|FIXME\"; then\n  echo \"WARNING: Committing TODO/FIXME\"\nfi\n\necho \"All checks passed!\"","description":"Pre-commit hook runs lint, format, secret scanning, and tests before each commit — Shift Left in action."},{"title":"CI with Shift Left Practices","useCase":"Comprehensive early testing.","code":"name: Shift Left CI\non: [pull_request]\n\njobs:\n  quality:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - run: npm ci\n      - name: Static Analysis\n        run: npm run lint && npm run lint:security\n      - name: Dependency Audit\n        run: npm audit --audit-level=high\n      - name: Unit Tests + Coverage\n        run: npm test -- --coverage --min-coverage=80\n      - name: Build Check\n        run: npm run build\n      - name: Contract Tests\n        run: npm run test:contract\n      - name: SAST Scan\n        uses: github/codeql-action/analyze@v2","description":"CI pipeline with Shift Left practices: static analysis, dependency audit, unit tests, contract tests, SAST scan."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the core idea behind Shift Left?","options":["Test after deployment","Move testing earlier in the lifecycle","Test only in production","Reduce test automation"],"answer":1,"explanation":"Shift Left moves testing activities earlier in the development lifecycle to catch defects sooner."},{"question":"How much more expensive is a bug found in production vs development?","options":["Same cost","2x more expensive","10-100x more expensive","Cheaper in production"],"answer":2,"explanation":"A defect found in production can cost 10-100x more to fix than one caught during development."},{"question":"What is SAST?","options":["Security testing during runtime","Static source code analysis for vulnerabilities","Penetration testing","User acceptance testing"],"answer":1,"explanation":"SAST (Static Application Security Testing) analyzes source code for vulnerabilities without executing it."},{"question":"Shift Left Testing — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Shift Left Testing — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Shift Left Testing — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Shift Left Testing — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Shift Left Testing — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Shift Left Testing — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Shift Left Testing — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-gitops"] = {"id":"devops-gitops","title":"GitOps","difficulty":"advanced","estimatedMinutes":25,"tldr":["GitOps is an operational framework that uses Git as the single source of truth for declarative infrastructure and applications.","The Git repository contains the entire desired state of the system. Automated process reconciles actual state with desired state.","Principles: declarative config, Git as source of truth, automated reconciliation, pull-based deployment, observability.","Tools: ArgoCD, Flux (Kubernetes), Terraform Cloud, Atlantis. Most commonly used with Kubernetes."],"laymanDefinition":"GitOps is like a house where the blueprint IS the house. You update the blueprint (Git repo), and robot builders (ArgoCD/Flux) immediately make the house match. If someone drills a wrong hole, robots detect and fix it. No one ever touches the actual house directly.","deepDive":[{"heading":"GitOps Principles","text":"Declarative: entire system described declaratively (K8s manifests, Terraform). Versioned: Git history is audit trail. Approved: changes go through PRs and code review. Automated: operator reconciles desired vs actual. Observable: system state visible, drift detected."},{"heading":"GitOps vs CI/CD","text":"CI/CD pushes changes (push model). GitOps pulls from Git (pull model). In GitOps, the cluster watches Git and self-heals. GitOps is declarative; traditional CI/CD is often imperative. GitOps is better for Kubernetes-native deployments."},{"heading":"ArgoCD","text":"Kubernetes controller monitoring Git repos and reconciling cluster state. Features: auto-sync, health checks, rollback, SSO, multi-cluster. App of Apps pattern."},{"heading":"Disaster Recovery","text":"Point a new cluster at the Git repo — GitOps automatically restores the entire desired state. No manual reconfiguration needed. Complete audit trail in Git history."}],"interviewAnswer":"GitOps is the standard for Kubernetes deployments. Use ArgoCD or Flux. Pull-based model is more secure. Disaster recovery is trivial — point a new cluster at Git. Never make changes directly to the cluster.","interviewQuestions":[{"question":"What is GitOps?","answer":"Using Git as the single source of truth for declarative infrastructure with automated reconciliation."},{"question":"What is the difference between GitOps and CI/CD?","answer":"CI/CD pushes to environments. GitOps pulls from Git. GitOps is pull-based and self-healing."},{"question":"What is ArgoCD?","answer":"A GitOps operator for Kubernetes that monitors Git repos and reconciles cluster state."},{"question":"How does GitOps help with disaster recovery?","answer":"Point a new cluster at Git — GitOps automatically restores everything."},{"question":"What is a pull-based deployment model?","answer":"The agent inside the cluster pulls desired state from Git rather than CI pushing to the cluster."},{"question":"GitOps — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"GitOps — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"GitOps — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"GitOps — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"GitOps — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">GitOps</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Developer</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Pushes to Git</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Repo</text><text x=\"215\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Source of truth</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GitOps Operator</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ArgoCD / Flux</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Kubernetes</text><text x=\"215\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Reconcile state</text><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pull Model</text><text x=\"65\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Agent pulls from Git</text><rect x=\"10\" y=\"135\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"151\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Drift Detect</text><text x=\"65\" y=\"143\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto-heal difference</text><text x=\"65\" y=\"154\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">s</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"135\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GitOps</text><text x=\"385\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Git = source of truth. Pull-based.</text><text x=\"385\" y=\"164\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> Self-healing. ArgoCD/Flux.</text><text x=\"240\" y=\"205\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">GitOps: Git is source of truth. Declarative + pull</text><text x=\"240\" y=\"217\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">-based + self-healing deployments.</text></svg>","codeExamples":[{"title":"ArgoCD Application","useCase":"GitOps app definition.","code":"apiVersion: argoproj.io/v1alpha1\nkind: Application\nmetadata:\n  name: myapp\n  namespace: argocd\nspec:\n  project: default\n  source:\n    repoURL: https://github.com/org/myapp.git\n    targetRevision: main\n    path: k8s/overlays/production\n  destination:\n    server: https://kubernetes.default.svc\n    namespace: production\n  syncPolicy:\n    automated:\n      prune: true\n      selfHeal: true","description":"ArgoCD Application CRD — defines Git repo source and destination cluster."},{"title":"Flux GitRepository","useCase":"Flux source definition.","code":"apiVersion: source.toolkit.fluxcd.io/v1\nkind: GitRepository\nmetadata:\n  name: myapp\n  namespace: flux-system\nspec:\n  interval: 1m\n  url: https://github.com/org/myapp.git\n  ref:\n    branch: main\n---\napiVersion: kustomize.toolkit.fluxcd.io/v1\nkind: Kustomization\nmetadata:\n  name: myapp\nspec:\n  interval: 10m\n  sourceRef:\n    kind: GitRepository\n    name: myapp\n  path: ./k8s/overlays/production\n  prune: true","description":"Flux GitRepository and Kustomization driving GitOps reconciliation."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is GitOps?","options":["Git version control","Git as source of truth for declarative infrastructure","Git-based project management","Git CI/CD"],"answer":1,"explanation":"GitOps uses Git as the single source of truth for declarative infrastructure with automated reconciliation."},{"question":"What model does GitOps use?","options":["Push model","Pull model","Hybrid model","Manual model"],"answer":1,"explanation":"GitOps uses a pull model where agents inside the cluster pull desired state from Git."},{"question":"What is ArgoCD?","options":["CI tool","GitOps operator for Kubernetes","Monitoring tool","Container runtime"],"answer":1,"explanation":"ArgoCD is a GitOps operator that monitors Git repos and reconciles Kubernetes cluster state."},{"question":"GitOps — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"GitOps — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"GitOps — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"GitOps — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"GitOps — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"GitOps — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"GitOps — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-devsecops"] = {"id":"devops-devsecops","title":"DevSecOps","difficulty":"intermediate","estimatedMinutes":20,"tldr":["DevSecOps integrates security into every phase of the DevOps lifecycle, making security a shared responsibility.","\"Shift Left on Security\" — security from the start, not bolted on as a final gate.","Practices: threat modeling, secure coding, SAST, DAST, SCA, container scanning, policy as code.","Replaces the traditional \"security gate\" model with continuous security validation throughout the pipeline."],"laymanDefinition":"DevSecOps is like building a house with a security system installed during construction, not after move-in. Security is part of every step: foundation is secure, walls are reinforced, locks are tested before the roof goes on.","deepDive":[{"heading":"SAST, DAST, SCA","text":"SAST (Static): analyze source code without execution (SonarQube, CodeQL, Semgrep). DAST (Dynamic): test running app (OWASP ZAP, Burp Suite). SCA (Composition): scan dependencies for CVEs (Snyk, npm audit, Trivy). All integrated into CI/CD."},{"heading":"Policy as Code","text":"Security policies as machine-readable code. OPA (Open Policy Agent) / Rego. Automated, consistent decisions. Examples: \"containers must not run as root\", \"all APIs must have rate limiting\", \"deployments must have resource limits\". Tested and versioned."},{"heading":"Container Security","text":"Image scanning for CVEs (Trivy, Clair). Build-time: no root user, minimal base images (distroless). Runtime: Falco (behavioral monitoring), AppArmor. Registry: only signed images. Admission control: Kyverno, OPA."}],"interviewAnswer":"DevSecOps makes security continuous and automated. Integrate SAST, DAST, SCA in CI/CD. Use policy as code (OPA). Scan containers. Shift security left. Security is everyone's responsibility.","interviewQuestions":[{"question":"What is DevSecOps?","answer":"Integrating security into every phase of the DevOps lifecycle as a shared responsibility."},{"question":"What is the difference between SAST and DAST?","answer":"SAST analyzes source code without execution. DAST tests running applications."},{"question":"What is SCA?","answer":"Software Composition Analysis — scanning dependencies for known vulnerabilities."},{"question":"What is Policy as Code?","answer":"Security policies defined as version-controlled, automated code enforced by tools like OPA."},{"question":"DevSecOps — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"DevSecOps — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"DevSecOps — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"DevSecOps — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"DevSecOps — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"DevSecOps — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">DevSecOps</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Code</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">SAST + lint</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dependencies</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">SCA</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Container scan</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">OPA policy</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Runtime</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Falco monitor</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DevSecOps</text><text x=\"270\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Security in every phase. SAST, DAST, SCA</text><text x=\"270\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">, container scanning, policy as code.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">DevSecOps: Security integrated throughout the pipe</text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">line. Automated, continuous, shared responsibility</text><text x=\"240\" y=\"244\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">.</text></svg>","codeExamples":[{"title":"Security Scanning in CI","useCase":"SAST + SCA + container scan.","code":"name: DevSecOps Pipeline\non: [push, pull_request]\njobs:\n  security:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - name: CodeQL Analysis\n        uses: github/codeql-action/analyze@v2\n      - name: Dependency Audit\n        run: npm audit --audit-level=high\n      - name: Snyk Scan\n        uses: snyk/actions/node@master\n      - name: Trivy Scan\n        uses: aquasecurity/trivy-action@master\n        with:\n          image-ref: \"myapp:${{ github.sha }}\"","description":"CI pipeline integrating SAST, SCA, and container scanning for continuous security."},{"title":"OPA Policy (Rego)","useCase":"Kubernetes admission policy.","code":"package kubernetes.admission\ndeny[msg] {\n  input.request.kind.kind == \"Pod\"\n  c := input.request.object.spec.containers[_]\n  not c.securityContext.runAsNonRoot\n  msg := sprintf(\"Container %v must runAsNonRoot\", [c.name])\n}\ndeny[msg] {\n  c := input.request.object.spec.containers[_]\n  not c.resources.limits\n  msg := sprintf(\"Container %v needs resource limits\", [c.name])\n}","description":"OPA/Rego policies enforcing security rules for Kubernetes admission control."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is DevSecOps?","options":["Separate security team","Security in every DevOps phase","Security only at deployment","Manual review"],"answer":1,"explanation":"DevSecOps integrates security into every phase of the DevOps lifecycle."},{"question":"What is SAST vs DAST?","options":["SAST=running app; DAST=source","SAST=source code; DAST=running app","Same thing","Both test dependencies"],"answer":1,"explanation":"SAST analyzes source code statically; DAST tests the running application dynamically."},{"question":"What is SCA?","options":["Static code analysis","Software Composition Analysis (dependency scanning)","System audit","Security audit"],"answer":1,"explanation":"SCA scans dependencies for known vulnerabilities. Tools: Snyk, npm audit, Trivy."},{"question":"DevSecOps — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"DevSecOps — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"DevSecOps — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"DevSecOps — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"DevSecOps — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"DevSecOps — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"DevSecOps — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-platform-engineering"] = {"id":"devops-platform-engineering","title":"Platform Engineering","difficulty":"advanced","estimatedMinutes":25,"tldr":["Platform Engineering builds and maintains internal developer platforms (IDPs) providing self-service capabilities for dev teams.","The platform abstracts infrastructure complexity, providing developers golden paths to deploy and manage applications.","Components: CI/CD pipelines, infrastructure automation, service catalog, developer portals (Backstage), observability, security.","DevOps is culture; platform engineering builds tools that enable that culture at scale."],"laymanDefinition":"Platform engineering is like building a supermarket instead of every chef growing their own food. Devs can \"pick up\" pre-configured services: PostgreSQL, Redis, Kubernetes namespace — all self-service, all compliant.","deepDive":[{"heading":"Internal Developer Platform (IDP)","text":"Self-service layer on top of infrastructure. Components: provisioning (Terraform), CI/CD, service catalog (Backstage), secrets, monitoring, cost tracking. IDP is the product; developers are the customers."},{"heading":"Golden Path","text":"The recommended, well-supported way to build and deploy services. Standardized tooling, templates, workflows. Reduces decision fatigue. Ensures best practices are followed automatically."},{"heading":"Backstage (Spotify)","text":"Open-source developer portal. Software catalog, templates (scaffold new services), plugins (CI/CD, monitoring, docs), techdocs. Unifies all dev tools into a single interface."},{"heading":"Platform as a Product","text":"Treat platform as a product: understand developer pain points, define SLIs/SLOs, gather feedback, iterate. Platform adoption is voluntary — make it better than alternatives."}],"interviewAnswer":"Platform engineering builds the internal tools that make DevOps scalable. Treat the platform as a product. Use Backstage for the developer portal. Build golden paths. Abstract complexity. Platform engineering and DevOps are complementary.","interviewQuestions":[{"question":"What is Platform Engineering?","answer":"Building internal developer platforms providing self-service capabilities for development teams."},{"question":"What is an IDP?","answer":"Internal Developer Platform — a self-service layer on top of infrastructure abstracting complexity for developers."},{"question":"What is a Golden Path?","answer":"The recommended, standardized way to build and deploy services with best practices built in."},{"question":"What is Backstage?","answer":"An open-source developer portal platform by Spotify with software catalog, templates, and plugins."},{"question":"What does \"platform as a product\" mean?","answer":"Treating the internal platform as a product with users, feedback loops, and continuous improvement."},{"question":"Platform Engineering — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Platform Engineering — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Platform Engineering — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Platform Engineering — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Platform Engineering — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Platform Engineering</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">IDP</text><text x=\"65\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Self-service platfor</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">m</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Golden Path</text><text x=\"65\" y=\"73\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Standardized workflo</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ws</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Backstage</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Developer portal</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Templates</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Scaffold services</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Catalog</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">All services tracked</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Platform Engineering</text><text x=\"385\" y=\"162\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Build IDPs. Self-service golden pa</text><text x=\"385\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ths. Platform as a product. Backst</text><text x=\"385\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">age. DevOps at scale.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Platform Engineering: Building IDPs for self-servi</text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ce, golden paths, and DevOps at scale.</text></svg>","codeExamples":[{"title":"Backstage Software Template","useCase":"Scaffold a new service.","code":"apiVersion: scaffolder.backstage.io/v1beta3\nkind: Template\nmetadata:\n  name: node-service\n  title: Node.js Microservice\nspec:\n  owner: platform-team\n  parameters:\n    - title: Service Details\n      required: [name, owner]\n      properties:\n        name:\n          title: Service Name\n          type: string\n        owner:\n          title: Team\n          type: string\n  steps:\n    - id: template\n      name: Scaffold\n      action: fetch:template\n      input:\n        url: ./templates/node-service\n        values:\n          name: ${{ parameters.name }}\n    - id: publish\n      name: Publish to GitHub\n      action: publish:github\n      input:\n        repoUrl: github.com?owner=${{ parameters.owner }}","description":"Backstage template scaffolding a new Node.js microservice with CI/CD and catalog registration."},{"title":"Platform Mission Statement","useCase":"IDP vision.","code":"# Internal Developer Platform — Mission\n## Vision\nDevelopers build, deploy, and operate services without leaving their IDE.\n## Principles\n- Self-service over tickets\n- Golden paths over unlimited flexibility\n- Automation over manual processes\n- Observability as default\n- Security baked in\n## Success Metrics\n- Onboard new service: < 1 hour\n- Dev satisfaction: NPS > 50\n- Platform uptime: 99.99%","description":"Platform team mission defining IDP vision, principles, and success metrics."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is Platform Engineering?","options":["Managing cloud infra","Building IDPs for self-service","Writing app code","Managing DBs"],"answer":1,"explanation":"Platform Engineering builds Internal Developer Platforms providing self-service capabilities."},{"question":"What is a Golden Path?","options":["Most secure path","Standardized way to build/deploy","Migration strategy","Testing approach"],"answer":1,"explanation":"A Golden Path is the recommended, standardized workflow for building and deploying services."},{"question":"What is Backstage?","options":["CI/CD tool","Open-source developer portal by Spotify","Monitoring tool","Container runtime"],"answer":1,"explanation":"Backstage is an open-source developer portal for software catalog, templates, and self-service."},{"question":"Platform Engineering — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Platform Engineering — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Platform Engineering — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Platform Engineering — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Platform Engineering — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Platform Engineering — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Platform Engineering — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-sre"] = {"id":"devops-sre","title":"SRE (Site Reliability Engineering)","difficulty":"advanced","estimatedMinutes":30,"tldr":["SRE applies software engineering principles to operations and infrastructure problems.","Originated at Google (2003). SRE teams are software engineers who design and build operational systems.","Core concepts: SLOs, SLIs, error budgets, toil elimination, automation, blameless postmortems.","SRE differs from traditional Ops: SREs are engineers who code, not sysadmins. They automate themselves out of manual work."],"laymanDefinition":"SRE is like having an engineer who builds self-cleaning houses instead of a janitor. The SRE writes software that monitors, fixes, and improves the house automatically. If something breaks, they build a robot to fix it forever.","deepDive":[{"heading":"SLOs, SLIs, Error Budgets","text":"SLI: quantitative measure (latency p99, error rate). SLO: target value (p99 < 200ms, 99.9% availability). Error Budget: allowable unreliability (100% - SLO). If budget is available, deploy risky changes. If depleted, stop deployments until reliability improves."},{"heading":"Toil Elimination","text":"Toil: manual, repetitive, automatable ops work (restarts, manual deploys, non-urgent alerts). SREs spend < 50% on toil. Rest is engineering to eliminate toil. Every toil task gets an automation ticket."},{"heading":"Blameless Postmortems","text":"Focus on what happened and why, not who. No blame. Action items are system improvements. Postmortems shared broadly. Culture of learning from failure."},{"heading":"SRE vs DevOps","text":"SRE: specific role/team with SLOs and error budgets. DevOps: broader cultural movement. SRE implements DevOps principles with specific practices. Google: \"SRE is what happens when you ask a software engineer to design an operations team.\""}],"interviewAnswer":"SRE applies engineering to ops. Define SLOs and error budgets. Automate toil. Blameless postmortems. < 50% time on toil. Reliability is a feature — manage it like one.","interviewQuestions":[{"question":"What is SRE?","answer":"Site Reliability Engineering — applying software engineering to operations and infrastructure."},{"question":"What is an SLO?","answer":"Service Level Objective — target value for a reliability metric (e.g., 99.9% availability)."},{"question":"What is an error budget?","answer":"Allowable unreliability (100% - SLO). If depleted, deployments stop until reliability improves."},{"question":"What is toil?","answer":"Manual, repetitive, automatable ops work. SREs spend < 50% time on toil."},{"question":"What is the difference between SRE and DevOps?","answer":"SRE is a specific role with SLOs/error budgets. DevOps is a broader cultural movement."},{"question":"SRE (Site Reliability Engineering) — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"SRE (Site Reliability Engineering) — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"SRE (Site Reliability Engineering) — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"SRE (Site Reliability Engineering) — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"SRE (Site Reliability Engineering) — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">SRE (Site Reliability Engineering)</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SLI</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Latency, error rate</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SLO</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">99.9% availability</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Error Budget</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">0.1% = 8.7h/year</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Automation</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Kill toil</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Postmortem</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Blameless learning</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SRE</text><text x=\"385\" y=\"162\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Software engineering for ops. SLOs</text><text x=\"385\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">, error budgets, toil elimination,</text><text x=\"385\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> blameless.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">SRE: Engineering applied to operations. SLO-driven</text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">, error budgets, automation, blameless postmortems</text><text x=\"240\" y=\"244\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">.</text></svg>","codeExamples":[{"title":"SLO Monitoring Rules (Prometheus)","useCase":"SLI-based alerting.","code":"groups:\n  - name: slo-alerts\n    rules:\n      - record: job:latency:p99\n        expr: histogram_quantile(0.99,\n          rate(http_duration_seconds_bucket[5m]))\n      - record: job:error_budget_burn\n        expr: (1 - job:availability:ratio) / (1 - 0.999)\n      - alert: ErrorBudgetDepleted\n        expr: error_budget_burn > 2\n        for: 1h\n        labels: { severity: critical }\n        annotations: { summary: \"Budget depleted\" }","description":"Prometheus rules for SLI, error budget burn rate, and SLO-based alerting."},{"title":"Incident Response Runbook","useCase":"SRE incident process.","code":"# Incident Runbook: Service Degraded\n## Severity: SEV2\n1. ACKNOWLEDGE: Acknowledge alert in PagerDuty\n2. TRIAGE: Check Grafana, recent deploys, error logs\n3. MITIGATE: Rollback if recent deploy, scale if traffic\n4. RESOLVE: Confirm fix, update PagerDuty\n5. POSTMORTEM: Schedule within 48h, write timeline\n\n# Severity levels\nSEV1: Critical user-facing outage\nSEV2: Major degradation\nSEV3: Minor non-urgent issue","description":"SRE incident response runbook with acknowledge, triage, mitigate, resolve, and postmortem."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What does SRE stand for?","options":["Site Reliability Engineering","Software Release Engineering","System Resource Engineering","Site Runtime Environment"],"answer":0,"explanation":"SRE = Site Reliability Engineering."},{"question":"What is an error budget?","options":["Budget for hiring","Allowable unreliability (100% - SLO)","Infrastructure budget","Team budget"],"answer":1,"explanation":"Error budget = 100% - SLO. It represents the allowable unreliability."},{"question":"How much time on toil?","options":["No limit","< 50%","> 80%","Exactly 50%"],"answer":1,"explanation":"SREs should spend no more than 50% of time on toil; the rest is engineering to eliminate it."},{"question":"SRE (Site Reliability Engineering) — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"SRE (Site Reliability Engineering) — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"SRE (Site Reliability Engineering) — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"SRE (Site Reliability Engineering) — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"SRE (Site Reliability Engineering) — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"SRE (Site Reliability Engineering) — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"SRE (Site Reliability Engineering) — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-blue-green"] = {"id":"devops-blue-green","title":"Blue-Green Deployment","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Blue-Green maintains two identical production environments — Blue (current live) and Green (new version).","Traffic routes to Blue. When Green is ready, the router switches all traffic from Blue to Green at once.","Benefits: zero-downtime, instant rollback (switch back to Blue), environment validation before traffic switch.","Challenge: double infrastructure cost, database schema changes need careful handling."],"laymanDefinition":"Blue-Green is like two identical bridges across a river. Traffic uses Blue. You build Green alongside. When Green is tested, switch all traffic instantly. If problems, switch back to Blue. Traffic never stops.","deepDive":[{"heading":"Architecture","text":"Two identical environments. Load balancer controls traffic direction. At switch time, router reconfigures to send all traffic to Green. Old Blue stays ready for rollback."},{"heading":"Database Challenges","text":"Schema changes must be backward-compatible. Phase migrations: add columns before switch, remove old after. Green connects to same DB or cloned replica. Best: changes compatible with N-1 version."},{"heading":"Switch and Rollback","text":"Switch: update DNS/load balancer to Green. Instant for internal LBs; DNS has propagation delay (use low TTL). Rollback: switch traffic back to Blue. Blue still running. No redeployment."},{"heading":"Kubernetes Blue-Green","text":"Two deployments (blue, green) with labels. Service selector switches between them. Tools: Argo Rollouts, Flagger automate traffic switching."}],"interviewAnswer":"Blue-Green provides zero-downtime deployments with instant rollback at double infrastructure cost. Database migrations must be backward-compatible. Use for critical services where downtime is unacceptable.","interviewQuestions":[{"question":"What is Blue-Green deployment?","answer":"Two identical environments. One live (Blue), one staging (Green). Traffic switches instantly from Blue to Green."},{"question":"What is the main benefit?","answer":"Zero-downtime deployments and instant rollback by switching traffic back to Blue."},{"question":"What is the main challenge?","answer":"Double infrastructure cost during transition. Both environments run simultaneously."},{"question":"How is rollback handled?","answer":"Switch traffic back to the still-running Blue environment. No redeployment needed."},{"question":"How to handle DB migrations?","answer":"Backward-compatible schema changes. Phase migrations: add before switch, remove old after."},{"question":"Blue-Green Deployment — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Blue-Green Deployment — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Blue-Green Deployment — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Blue-Green Deployment — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Blue-Green Deployment — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Blue-Green Deployment</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Blue</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Current live (v1)</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Green</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New version (v2)</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Load Balancer</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Routes traffic</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Users</text><text x=\"215\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">100% Blue</text><rect x=\"160\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"215\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Switch Green</text><text x=\"215\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">100% Green</text><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"130\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rollback</text><text x=\"65\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Switch back to Blue</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"130\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Blue-Green</text><text x=\"385\" y=\"137\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Zero-downtime. Double cost. Instan</text><text x=\"385\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">t rollback. Backward-compatible DB</text><text x=\"385\" y=\"159\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">.</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Blue-Green: Two environments, instant switch. Zero</text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> downtime, instant rollback.</text></svg>","codeExamples":[{"title":"K8s Blue-Green Service","useCase":"Service selector switching.","code":"apiVersion: v1\nkind: Service\nmetadata:\n  name: myapp\nspec:\n  selector:\n    app: myapp\n    version: blue  # change to green\n  ports:\n    - port: 80\n---\napiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: myapp-blue\nspec:\n  replicas: 3\n  selector:\n    matchLabels:\n      app: myapp\n      version: blue\n  template:\n    metadata:\n      labels:\n        app: myapp\n        version: blue\n    spec:\n      containers:\n        - name: app\n          image: myapp:1.0.0","description":"K8s Service + Deployment for Blue-Green. Change selector from blue to green to switch traffic."},{"title":"Argo Rollouts BlueGreen","useCase":"Automated Blue-Green.","code":"apiVersion: argoproj.io/v1alpha1\nkind: Rollout\nmetadata:\n  name: myapp-rollout\nspec:\n  replicas: 5\n  strategy:\n    blueGreen:\n      activeService: myapp-blue\n      previewService: myapp-green\n      autoPromotionEnabled: false\n      prePromotionAnalysis:\n        templates:\n          - templateName: smoke-test\n      scaleDownDelaySeconds: 600\n  selector:\n    matchLabels:\n      app: myapp\n  template:\n    metadata:\n      labels:\n        app: myapp\n    spec:\n      containers:\n        - name: app\n          image: myapp:2.0.0","description":"Argo Rollouts BlueGreen strategy with preview service, smoke tests, and delayed scale-down."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the main benefit of Blue-Green?","options":["Lower cost","Zero-downtime + instant rollback","Faster builds","Less testing"],"answer":1,"explanation":"Blue-Green provides zero-downtime deployments and instant rollback by switching traffic."},{"question":"What is the main disadvantage?","options":["Slower deploys","Double infrastructure cost","More bugs","Less testing"],"answer":1,"explanation":"Blue-Green requires two full environments, doubling infrastructure costs during transition."},{"question":"How does Blue-Green handle rollback?","options":["Redeploy old version","Switch traffic back to Blue","Restore DB backup","Rebuild Green"],"answer":1,"explanation":"Rollback is instant — switch traffic back to the still-running Blue environment."},{"question":"Blue-Green Deployment — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Blue-Green Deployment — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Blue-Green Deployment — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Blue-Green Deployment — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Blue-Green Deployment — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Blue-Green Deployment — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Blue-Green Deployment — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-canary"] = {"id":"devops-canary","title":"Canary Deployment","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Canary deployment gradually rolls out a new version to a small subset of users before expanding to everyone.","Named from \"canary in a coal mine\" — early detection protects all users.","Traffic increments: 1% → 5% → 10% → 25% → 50% → 100%, with monitoring and auto-rollback at each stage.","Tools: Argo Rollouts, Flagger, Istio, NGINX Plus, AWS CodeDeploy, LaunchDarkly."],"laymanDefinition":"Canary is like testing a new roller coaster on employees first. If 1% enjoy it safely, let 5% ride. Then 25%. Then everyone. If someone gets sick at 5%, stop immediately and fix it before anyone else rides.","deepDive":[{"heading":"Process","text":"Deploy new version alongside old. Start with 1% traffic. Monitor metrics (error rate, latency, business). If healthy: increase to 5%, 10%, 25%, 50%, 100%. If any metric degrades: auto-rollback."},{"heading":"Metrics for Analysis","text":"Error rate (5xx), latency (p50/p95/p99), CPU/memory, business metrics (conversion, sign-ups). Compare canary vs baseline. Statistically significant difference triggers rollback."},{"heading":"Service Mesh Canary (Istio)","text":"VirtualService routes traffic by weight percentage. DestinationRule defines subsets. Traffic splitting via weight updates. Istio handles metrics, retries, circuit breaking."},{"heading":"Canary vs Blue-Green","text":"Canary: gradual, risk-reducing, metrics-driven. Blue-Green: instant switch, simpler. Canary better for high-risk changes. Blue-Green for low-risk, instant-switch acceptable."}],"interviewAnswer":"Canary deployments reduce risk by gradual exposure. Start small, monitor metrics, expand if healthy, rollback if not. Use service mesh for fine-grained traffic control. Argo Rollouts and Flagger automate the process.","interviewQuestions":[{"question":"What is Canary deployment?","answer":"Gradually rolling out a new version to a small subset before expanding to everyone."},{"question":"Why \"canary\"?","answer":"From \"canary in a coal mine\" — early group catches problems before affecting everyone."},{"question":"What triggers auto-rollback?","answer":"Metric degradation: error rate, latency, or business metrics exceeding thresholds."},{"question":"What is the difference between Canary and Blue-Green?","answer":"Canary is gradual; Blue-Green is instant switch. Canary needs sophisticated traffic routing."},{"question":"Canary Deployment — What tools integrate well with this?","answer":"Integration is possible through APIs, plugins, webhooks, and configuration files."},{"question":"Canary Deployment — What are common troubleshooting steps?","answer":"Troubleshooting involves checking logs, verifying configuration, and testing incrementally."},{"question":"Canary Deployment — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Canary Deployment — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Canary Deployment — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Canary Deployment — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Canary Deployment</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 1</text><text x=\"65\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Deploy v2 alongside </text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">v1</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 2</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">1% traffic to v2</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 3</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Monitor metrics</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 4</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">5%, 10%, 25%...</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 5</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">100% or Rollback</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Canary</text><text x=\"270\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Gradual: 1% → 5% → 100%. Auto-rollback o</text><text x=\"270\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">n metric degradation.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Canary: Gradual rollout with metrics-driven promot</text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ion. Start small, expand if healthy.</text></svg>","codeExamples":[{"title":"Istio Canary VirtualService","useCase":"Weight-based traffic split.","code":"apiVersion: networking.istio.io/v1beta1\nkind: VirtualService\nmetadata:\n  name: myapp\nspec:\n  hosts: [myapp]\n  http:\n    - route:\n        - destination:\n            host: myapp\n            subset: v1\n          weight: 95\n        - destination:\n            host: myapp\n            subset: v2\n          weight: 5\n---\napiVersion: networking.istio.io/v1beta1\nkind: DestinationRule\nmetadata:\n  name: myapp\nspec:\n  host: myapp\n  subsets:\n    - name: v1\n      labels: { version: v1 }\n    - name: v2\n      labels: { version: v2 }","description":"Istio VirtualService routes 5% traffic to v2 canary, 95% to v1 stable."},{"title":"Argo Rollouts Canary","useCase":"Automated canary steps.","code":"apiVersion: argoproj.io/v1alpha1\nkind: Rollout\nmetadata:\n  name: myapp-canary\nspec:\n  strategy:\n    canary:\n      steps:\n        - setWeight: 5\n        - pause: {duration: 5m}\n        - setWeight: 25\n        - pause: {duration: 5m}\n        - setWeight: 100\n      analysis:\n        templates:\n          - templateName: success-rate","description":"Argo Rollouts canary with stepped weight increases and analysis-driven auto-promotion."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is Canary deployment?","options":["Deploy to all at once","Gradual rollout to subset first","Rollback after release","Staging only"],"answer":1,"explanation":"Canary gradually rolls out to a small subset before expanding."},{"question":"What triggers auto-rollback?","options":["Time elapsed","Metric degradation","User complaints","Manual decision"],"answer":1,"explanation":"If metrics (error rate, latency) exceed thresholds, the canary auto-rollbacks."},{"question":"What tool provides service mesh canary?","options":["Docker","Istio","Ansible","Terraform"],"answer":1,"explanation":"Istio service mesh provides fine-grained weight-based traffic splitting for canary deployments."},{"question":"Canary Deployment — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Canary Deployment — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Canary Deployment — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Canary Deployment — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Canary Deployment — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Canary Deployment — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Canary Deployment — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-rolling"] = {"id":"devops-rolling","title":"Rolling Deployment","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Rolling deployment gradually replaces instances of the previous version with the new version one by one.","Unlike Blue-Green (instant switch) or Canary (subset exposure), rolling updates instances incrementally with no additional environment.","Kubernetes uses rolling updates by default — pods are replaced incrementally with zero downtime.","Benefits: no additional infrastructure cost, zero-downtime, gradual. Challenge: slow rollback (must roll instance by instance)."],"laymanDefinition":"Rolling deployment is like changing tires on a moving car. You replace one tire at a time while the car keeps driving. At any moment, most tires are the old ones, but gradually all become new. If the new tires vibrate, you must replace them back one at a time.","deepDive":[{"heading":"Kubernetes Rolling Update","text":"Default deployment strategy. Parameters: maxSurge (extra pods above desired), maxUnavailable (pods that can be down during update). Example: maxSurge=25%, maxUnavailable=25%. New ReplicaSet created. Old scaled down, new scaled up incrementally."},{"heading":"Rolling Update Process","text":"1. New ReplicaSet created with 0 replicas. 2. Old ReplicaSet scaled down by maxUnavailable. 3. New ReplicaSet scaled up by maxSurge. 4. Repeat until all pods are on new version. 5. Old ReplicaSet scaled to 0. Progress monitored via kubectl rollout status."},{"heading":"Rolling vs Blue-Green vs Canary","text":"Rolling: incremental instance replacement, no extra cost, slow rollback. Blue-Green: two full environments, instant rollback, double cost. Canary: traffic-based percentage, sophisticated routing, auto-rollback on metrics."},{"heading":"Rollback","text":"kubectl rollout undo deployment/myapp. Reverses the rolling update instance by instance. Slower than Blue-Green rollback. Can specify --to-revision for specific version. History kept (default: 10 revisions)."}],"interviewAnswer":"Rolling deployment is the default Kubernetes strategy. Zero extra cost, zero downtime, but slow rollback. Best for: stateless services, when you don't need instant rollback. Configure maxSurge/maxUnavailable based on capacity requirements.","interviewQuestions":[{"question":"What is Rolling deployment?","answer":"Gradually replacing instances of the old version with the new version one by one."},{"question":"What is the main benefit of Rolling?","answer":"No additional infrastructure cost — uses the same number of instances, just incrementally updated."},{"question":"What is the main disadvantage?","answer":"Slow rollback — must reverse the update instance by instance."},{"question":"What is maxSurge in Kubernetes?","answer":"Maximum number of extra pods that can be created above the desired count during a rolling update."},{"question":"What is maxUnavailable?","answer":"Maximum number of pods that can be unavailable during a rolling update."},{"question":"How do you rollback a rolling update?","answer":"kubectl rollout undo deployment/myapp."},{"question":"Rolling Deployment — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Rolling Deployment — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Rolling Deployment — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Rolling Deployment — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Rolling Deployment</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">v1 (old)</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">5 running pods</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">v2 (new)</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">0 pods</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rolling</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Replace 1 by 1</text><line x1=\"120\" y1=\"75\" x2=\"150\" y2=\"75\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"150\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"235\" y=\"53\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 1: +1 v2 pod (maxSurge)</text><rect x=\"160\" y=\"65\" width=\"150\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"235\" y=\"83\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 2: -1 v1 pod (maxUnavail)</text><rect x=\"160\" y=\"95\" width=\"150\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"235\" y=\"113\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 3: Repeat until all v2</text><rect x=\"10\" y=\"130\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"65\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rollback</text><text x=\"65\" y=\"138\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">undo instance by ins</text><text x=\"65\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">tance</text><rect x=\"320\" y=\"35\" width=\"160\" height=\"130\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"400\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rolling Update</text><text x=\"400\" y=\"137\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Incremental pod replacement. </text><text x=\"400\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Zero extra cost. Zero downtim</text><text x=\"400\" y=\"159\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">e. Slow rollback.</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Rolling: Replace instances incrementally. Default </text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">in Kubernetes. Zero extra cost, zero downtime.</text></svg>","codeExamples":[{"title":"Kubernetes Rolling Update Config","useCase":"Rolling update parameters.","code":"apiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: myapp\nspec:\n  replicas: 5\n  strategy:\n    type: RollingUpdate\n    rollingUpdate:\n      maxSurge: 1\n      maxUnavailable: 0\n  selector:\n    matchLabels:\n      app: myapp\n  template:\n    metadata:\n      labels:\n        app: myapp\n    spec:\n      containers:\n        - name: app\n          image: myapp:2.0.0","description":"Kubernetes deployment with RollingUpdate strategy. maxSurge=1 creates one extra pod at a time."},{"title":"Rolling Update Commands","useCase":"Manage rolling updates.","code":"# Trigger rolling update (update image)\nkubectl set image deployment/myapp\n  app=myapp:2.0.0\n\n# Check rollout status\nkubectl rollout status deployment/myapp\n\n# Pause rollout\nkubectl rollout pause deployment/myapp\n\n# Resume rollout\nkubectl rollout resume deployment/myapp\n\n# Rollback to previous version\nkubectl rollout undo deployment/myapp\n\n# Rollback to specific revision\nkubectl rollout undo deployment/myapp\n  --to-revision=2\n\n# View rollout history\nkubectl rollout history deployment/myapp","description":"Commands for managing rolling updates: trigger, monitor, pause, resume, and rollback."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the main benefit of Rolling deployment?","options":["Instant rollback","No additional infrastructure cost","Double environment","Traffic routing"],"answer":1,"explanation":"Rolling deployment uses the same number of instances, just updated incrementally — no extra cost."},{"question":"What is the main disadvantage?","options":["Higher cost","Slow rollback","Downtime","Complex setup"],"answer":1,"explanation":"Rollback is slow — must reverse the update instance by instance, unlike Blue-Green\\'s instant switch."},{"question":"What Kubernetes parameter controls extra pods?","options":["maxUnavailable","maxSurge","replicas","minReadySeconds"],"answer":1,"explanation":"maxSurge controls how many extra pods can be created above the desired count during rolling update."},{"question":"Rolling Deployment — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Rolling Deployment — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Rolling Deployment — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Rolling Deployment — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Rolling Deployment — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Rolling Deployment — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Rolling Deployment — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-recreate"] = {"id":"devops-recreate","title":"Recreate Deployment","difficulty":"beginner","estimatedMinutes":10,"tldr":["Recreate deployment terminates all running instances of the old version and then creates instances of the new version.","Simplest deployment strategy — results in downtime because all old pods are killed before new ones start.","Suitable for: development environments, batch jobs, stateful applications where versions cannot run concurrently.","In Kubernetes: strategy type: Recreate. Kills all old pods, then creates new pods."],"laymanDefinition":"Recreate deployment is like renovating a restaurant by closing it completely, demolishing everything, and building a new restaurant from scratch. Customers (traffic) cannot enter during renovation (downtime). It is simple but causes a complete service interruption.","deepDive":[{"heading":"Recreate Process","text":"1. All old pods are terminated simultaneously (or gracefully). 2. Wait for all old pods to be completely removed. 3. New pods are created from the new image. 4. Service becomes available again when new pods are ready. Total downtime: termination time + startup time."},{"heading":"When to Use Recreate","text":"Development/staging environments (downtime acceptable). Batch jobs and workers (no live traffic). Stateful applications where two versions cannot coexist (DB schema incompatible, migration required). Applications needing a clean slate (cache clear, reset connections)."},{"heading":"Recreate vs Rolling","text":"Recreate: downtime, simple, all-at-once replacement. Rolling: zero-downtime, incremental, more complex. Recreate avoids issues of running two versions simultaneously. Choose Recreate when downtime is acceptable and version coexistence is problematic."},{"heading":"Graceful Shutdown","text":"Kubernetes respects preStop hooks and terminationGracePeriodSeconds. Pod gets SIGTERM, waits for hook, then SIGKILL after grace period. Important for cleanup: close DB connections, finish in-flight requests, flush logs."}],"interviewAnswer":"Recreate is the simplest deployment strategy with guaranteed downtime. Use for dev environments or stateful apps that cannot run two versions. Graceful shutdown is critical to prevent data loss. Not suitable for production services requiring high availability.","interviewQuestions":[{"question":"What is Recreate deployment?","answer":"Terminate all old version instances, then create new version instances. Causes downtime."},{"question":"When would you use Recreate?","answer":"Dev environments, batch jobs, stateful applications where versions cannot coexist."},{"question":"What is the main disadvantage?","answer":"Downtime — no traffic is served during the transition."},{"question":"What is the main advantage?","answer":"Simplicity — no need to handle two versions running simultaneously."},{"question":"What is a preStop hook?","answer":"A command or HTTP request executed before a pod is terminated, for graceful cleanup."},{"question":"What is terminationGracePeriodSeconds?","answer":"Time Kubernetes waits after SIGTERM before sending SIGKILL (default: 30s)."},{"question":"Recreate Deployment — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Recreate Deployment — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Recreate Deployment — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Recreate Deployment — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Recreate Deployment</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Old v1</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">5 running pods</text><line x1=\"120\" y1=\"75\" x2=\"150\" y2=\"75\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"140\" height=\"50\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"230\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 1: Terminate ALL v1</text><text x=\"230\" y=\"79\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Downtime starts</text><line x1=\"300\" y1=\"60\" x2=\"310\" y2=\"60\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"320\" y=\"35\" width=\"110\" height=\"50\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"375\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 2: Create ALL v2</text><text x=\"375\" y=\"79\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Downtime ends</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Downtime</text><text x=\"65\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Total: term + startu</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">p</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">preStop</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Graceful cleanup</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Use Case</text><text x=\"65\" y=\"163\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Dev / stateful / bat</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ch</text><rect x=\"280\" y=\"100\" width=\"150\" height=\"80\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"355\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Recreate</text><text x=\"355\" y=\"152\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Simple. Complete downtime. </text><text x=\"355\" y=\"163\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">All old killed, then new cr</text><text x=\"355\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">eated.</text><text x=\"240\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Recreate: Kill all old, create all new. Simple but</text><text x=\"240\" y=\"222\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> causes downtime. For dev/stateful apps.</text></svg>","codeExamples":[{"title":"Kubernetes Recreate Strategy","useCase":"Recreate deployment config.","code":"apiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: myapp\nspec:\n  replicas: 3\n  strategy:\n    type: Recreate\n  selector:\n    matchLabels:\n      app: myapp\n  template:\n    metadata:\n      labels:\n        app: myapp\n    spec:\n      terminationGracePeriodSeconds: 60\n      containers:\n        - name: app\n          image: myapp:2.0.0\n          lifecycle:\n            preStop:\n              exec:\n                command:\n                  - /bin/sh\n                  - -c\n                  - \"sleep 10 && nginx -s quit\"","description":"Kubernetes Recreate strategy with preStop hook for graceful shutdown and 60s grace period."},{"title":"Graceful Shutdown Script","useCase":"PreStop hook example.","code":"#!/bin/bash\n# preStop.sh — graceful shutdown\n\necho \"Shutting down gracefully...\"\n\n# Stop accepting new connections\n# (already done by k8s removing from service)\n\n# Wait for in-flight requests to complete\nsleep 5\n\n# Close database connections\n# psql -c \"SELECT pg_terminate_backend(pid)\"\n\n# Flush logs\n# kill -USR1 $(cat /var/run/nginx.pid)\n\n# Stop the application process\n# kill -TERM $(cat /var/run/app.pid)\n\necho \"Shutdown complete\"","description":"Graceful shutdown script for Recreate deployment — drain connections, flush, then terminate."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is the key characteristic of Recreate deployment?","options":["Zero downtime","Complete downtime","Gradual replacement","Traffic splitting"],"answer":1,"explanation":"Recreate kills all old pods before creating new ones, resulting in complete downtime."},{"question":"When is Recreate appropriate?","options":["Production with high traffic","Dev environments and stateful apps","All scenarios","Only with Blue-Green"],"answer":1,"explanation":"Recreate is suitable for dev environments, batch jobs, and stateful apps where version coexistence is problematic."},{"question":"What does terminationGracePeriodSeconds control?","options":["Pod startup time","Time between SIGTERM and SIGKILL","Replica count","Health check interval"],"answer":1,"explanation":"It controls how long Kubernetes waits after SIGTERM before forcefully killing with SIGKILL."},{"question":"Recreate Deployment — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Recreate Deployment — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Recreate Deployment — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Recreate Deployment — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Recreate Deployment — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Recreate Deployment — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Recreate Deployment — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-feature-flags"] = {"id":"devops-feature-flags","title":"Feature Flags","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Feature flags (feature toggles) are a technique that turns functionality on/off without deploying new code.","They decouple deployment from release — you can deploy code that is \"dark\" (inactive) and release it later by flipping a flag.","Types: release flags, experiment flags, ops flags, permission flags. Each serves a different purpose.","Tools: LaunchDarkly, Split.io, Unleash, Flagsmith, custom implementation with config files or env vars."],"laymanDefinition":"Feature flags are like light switches for your application features. You install the light fixture (deploy code) but keep the switch off. Later, flip the switch (enable flag) to turn on the light without any electrical work. You can also dim (gradually roll out) or turn off instantly if something goes wrong.","deepDive":[{"heading":"Types of Feature Flags","text":"Release flags: toggle incomplete features (trunk-based dev). Experiment flags: A/B testing, canary, percentage rollouts. Ops flags: kill switches, maintenance mode, degrade functionality. Permission flags: control feature access by user tier/role (premium features)."},{"heading":"Feature Flag Best Practices","text":"Use short-lived flags for releases (remove after feature stabilizes). Use long-lived flags for ops (kill switches). Name flags clearly and consistently. Log flag evaluations for debugging. Monitor flag flips (who changed what). Avoid flag-induced tech debt — clean up old flags."},{"heading":"Feature Flags vs Branching","text":"Feature flags enable trunk-based development — no long-lived branches. Instead of \"merge when ready\", you deploy continuously and release with flags. Benefits: fewer merge conflicts, continuous integration, instant rollback (flip flag off). Flags are superior to feature branches for most cases."},{"heading":"Canary Releases with Flags","text":"Flags can enable gradual rollouts: enable for 1% of users, monitor, increase to 10%, 50%, 100%. User targeting: enable for internal users first, then beta, then all. Rollback: disable the flag — instant, no redeployment needed. Combine with deployment strategies for maximum safety."}],"interviewAnswer":"Feature flags decouple deployment from release. Deploy continuously, release when ready. Trunk-based development. Instant rollback by flipping a flag. Use short-lived flags for features, long-lived flags for ops. Clean up old flags to avoid tech debt.","interviewQuestions":[{"question":"What are feature flags?","answer":"Technique to turn functionality on/off without deploying new code, decoupling deployment from release."},{"question":"What are the types of feature flags?","answer":"Release flags, experiment flags, ops flags, permission flags."},{"question":"How do feature flags enable trunk-based development?","answer":"No long-lived branches. Deploy incomplete features behind flags, enable when ready."},{"question":"What is a kill switch?","answer":"An ops flag that disables a feature instantly if it causes problems in production (instant rollback)."},{"question":"What is a best practice for release flags?","answer":"Short-lived — remove after the feature is fully rolled out and stable."},{"question":"What is LaunchDarkly?","answer":"A commercial feature flag platform with targeting, percentage rollouts, and A/B testing capabilities."},{"question":"Feature Flags — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Feature Flags — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Feature Flags — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Feature Flags — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Feature Flags</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Code Deployed</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Behind flag = OFF</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Flag System</text><text x=\"215\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">LaunchDarkly / Unlea</text><text x=\"215\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">sh</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Flag ON →</text><text x=\"65\" y=\"78\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Feature active for u</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">sers</text><rect x=\"10\" y=\"100\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Flag OFF →</text><text x=\"65\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Feature hidden/deact</text><text x=\"65\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ivated</text><rect x=\"10\" y=\"130\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rollback</text><text x=\"65\" y=\"138\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Disable flag = insta</text><text x=\"65\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">nt</text><rect x=\"10\" y=\"160\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Clean Up</text><text x=\"65\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Remove flag after st</text><text x=\"65\" y=\"179\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">able</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Feature Flags</text><text x=\"385\" y=\"162\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Decouple deploy from release. Depl</text><text x=\"385\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">oy dark, release with flag. Instan</text><text x=\"385\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">t rollback. Trunk-based dev.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Feature Flags: Toggle features without redeploying</text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">. Deploy continuously, release when ready.</text></svg>","codeExamples":[{"title":"Feature Flag in Code (LaunchDarkly)","useCase":"Simple flag check.","code":"const launchdarkly = require('@launchdarkly/node-server-sdk');\n\nconst client = launchdarkly.init(process.env.LD_SDK_KEY);\n\napp.get('/api/checkout', async (req, res) => {\n  const user = { key: req.userId };\n\n  // Check if new checkout is enabled for user\n  const useNewCheckout = await client.variation(\n    'new-checkout-flow', user, false\n  );\n\n  if (useNewCheckout) {\n    return handleNewCheckout(req, res);\n  }\n\n  return handleOldCheckout(req, res);\n});","description":"LaunchDarkly feature flag check — routes to new or old checkout flow based on flag."},{"title":"Custom Feature Flag with Config","useCase":"Simple file-based flags.","code":"// flags.json — feature flag configuration\n{\n  \"new-checkout-flow\": {\n    \"enabled\": false,\n    \"users\": [\"preview_user_1\", \"preview_user_2\"],\n    \"percentage\": 0\n  },\n  \"dark-mode\": {\n    \"enabled\": true,\n    \"users\": [],\n    \"percentage\": 100\n  },\n  \"maintenance-mode\": {\n    \"enabled\": false  // kill switch\n  }\n}\n\n// Check flag in code\nfunction isEnabled(flagName, userId) {\n  const flag = flags[flagName];\n  if (!flag) return false;\n  if (flag.users?.includes(userId)) return true;\n  if (flag.enabled) return true;\n  return false;\n}","description":"Simple JSON-based feature flag implementation with user targeting and percentage rollout support."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What do feature flags decouple?","options":["Frontend from backend","Deployment from release","Testing from building","Monitoring from alerting"],"answer":1,"explanation":"Feature flags decouple deployment (deploy code) from release (enable for users)."},{"question":"What is a kill switch flag?","options":["A flag that deletes code","An ops flag that instantly disables problematic features","A flag that kills processes","A security flag"],"answer":1,"explanation":"A kill switch is an ops flag that instantly disables a feature if it causes problems."},{"question":"What happens to release flags after stabilization?","options":["Keep forever","Remove/clean up","Convert to ops flag","Ignore"],"answer":1,"explanation":"Release flags should be short-lived and removed after the feature is fully rolled out and stable."},{"question":"Feature Flags — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Feature Flags — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Feature Flags — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Feature Flags — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Feature Flags — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Feature Flags — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Feature Flags — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-release-mgmt"] = {"id":"devops-release-mgmt","title":"Release Management","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Release management is the process of planning, scheduling, controlling, and deploying software releases across environments.","It ensures releases are delivered predictably, with quality, and with minimal disruption to users.","Key activities: versioning, changelog generation, release planning, environment promotion, deployment coordination, release communication.","Release management bridges development (building) and operations (running) — it is the \"release\" phase in the DevOps lifecycle."],"laymanDefinition":"Release management is like planning a product launch event. You decide what goes into the launch (features), set the date, prepare the venue (environments), invite attendees (users), rehearse (test), and execute the launch. If something goes wrong, you have a backup plan (rollback).","deepDive":[{"heading":"Release Process","text":"1. Feature complete on main branch. 2. CI runs full test suite. 3. Create release branch (git flow) or tag. 4. Bump version (semantic versioning). 5. Generate changelog/release notes. 6. Deploy to staging/QA environment. 7. Integration, regression, and acceptance testing. 8. Release approval (change advisory board or automated). 9. Deploy to production. 10. Monitor for issues. 11. Post-release review."},{"heading":"Semantic Versioning (SemVer)","text":"MAJOR.MINOR.PATCH. MAJOR: incompatible API changes. MINOR: backward-compatible features. PATCH: backward-compatible bug fixes. Pre-release: 1.0.0-alpha, 1.0.0-beta, 1.0.0-rc.1. Build metadata: 1.0.0+build.123. Follow SemVer strictly for clear dependency management."},{"heading":"Release Cadence","text":"Fixed schedule: releases every 2 weeks/month (predictable). Continuous: release as soon as ready (DevOps ideal). Hybrid: fixed schedule but urgent fixes released immediately. Choose based on business needs, compliance requirements, and team maturity."},{"heading":"Release Gates","text":"Quality gates: all tests pass, code coverage threshold, no critical vulnerabilities. Approval gates: manual sign-off from QA, product owner, security. Environment gates: must pass staging before production. Each gate is a checkpoint that can stop the release if criteria not met."},{"heading":"Release Automation","text":"CI/CD pipeline automates most release steps. Release orchestration tools: Jenkins, Spinnaker, Harness. Artifact management: Nexus, Artifactory, Docker Hub. Changelog: auto-generated from conventional commits (git-cliff, semantic-release). Version bumping: automated by CI."}],"interviewAnswer":"Release management ensures predictable, high-quality releases. Use semantic versioning. Automate the release process. Define release gates. Choose a cadence that balances velocity with stability. Communicate release plans and results to stakeholders.","interviewQuestions":[{"question":"What is release management?","answer":"Planning, scheduling, controlling, and deploying software releases across environments."},{"question":"What is Semantic Versioning?","answer":"MAJOR.MINOR.PATCH versioning. MAJOR: breaking changes. MINOR: new features. PATCH: bug fixes."},{"question":"What is a release gate?","answer":"A checkpoint that a release must pass before proceeding to the next environment or phase."},{"question":"What is a release cadence?","answer":"The frequency and schedule of releases — fixed schedule, continuous, or hybrid."},{"question":"What is an artifact repository?","answer":"A system storing build artifacts (JARs, Docker images, npm packages). Examples: Nexus, Artifactory."},{"question":"What is conventional commits?","answer":"A commit message convention that enables automated changelog generation and version bumping."},{"question":"Release Management — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Release Management — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Release Management — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Release Management — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Release Management</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"18\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Plan</text><text x=\"65\" y=\"47\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">What goes in release</text><rect x=\"10\" y=\"58\" width=\"110\" height=\"18\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"74\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build</text><text x=\"65\" y=\"70\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Version + changelog</text><rect x=\"10\" y=\"81\" width=\"110\" height=\"18\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"97\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Test</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Staging + QA gates</text><rect x=\"10\" y=\"104\" width=\"110\" height=\"18\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"120\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Approve</text><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Sign-off checks</text><rect x=\"10\" y=\"127\" width=\"110\" height=\"18\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"143\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy</text><text x=\"65\" y=\"139\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Production release</text><rect x=\"10\" y=\"150\" width=\"110\" height=\"18\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"166\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Monitor</text><text x=\"65\" y=\"162\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Verify + rollback?</text><line x1=\"120\" y1=\"44\" x2=\"150\" y2=\"44\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"67\" x2=\"150\" y2=\"67\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"90\" x2=\"150\" y2=\"90\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"113\" x2=\"150\" y2=\"113\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"136\" x2=\"150\" y2=\"136\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"159\" x2=\"150\" y2=\"159\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"230\" height=\"150\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"275\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Release Management</text><text x=\"275\" y=\"157\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Plan → Build → Test → Approve → Deploy → </text><text x=\"275\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Monitor. SemVer, gates, automation, caden</text><text x=\"275\" y=\"179\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ce.</text><text x=\"240\" y=\"215\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Release Management: Predictable, high-quality rele</text><text x=\"240\" y=\"227\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ases. Planning, automation, and coordination.</text></svg>","codeExamples":[{"title":"Release Pipeline (Jenkins)","useCase":"Declarative release pipeline.","code":"pipeline {\n  agent any\n  stages {\n    stage('Version & Changelog') {\n      steps {\n        sh 'npx semantic-release --dry-run'\n      }\n    }\n    stage('Build & Package') {\n      steps { sh 'npm run build' }\n    }\n    stage('Deploy to Staging') {\n      steps {\n        sh 'kubectl set image deploy/myapp myapp=$IMAGE_TAG -n staging'\n      }\n    }\n    stage('Integration Tests') {\n      steps { sh 'npm run test:integration' }\n    }\n    stage('Security Scan') {\n      steps { sh 'trivy image myapp:$IMAGE_TAG' }\n    }\n    stage('Approval') {\n      input message: \"Approve production release?\"\n    }\n    stage('Deploy to Production') {\n      steps {\n        sh 'kubectl set image deploy/myapp myapp=$IMAGE_TAG -n prod'\n      }\n    }\n  }\n}","description":"Jenkins release pipeline with versioning, builds, staging deploy, tests, approval, and production deploy."},{"title":"Automated Changelog (conventional commits)","useCase":"Generate release notes.","code":"# .cliff.toml — git-cliff configuration\n[changelog]\nheader = \"# Changelog\"\nbody = \"## [{{ version }}] - {{ timestamp }}\"\n\n[[commit_generators]]\npattern = \"^(feat|fix|perf|refactor)\\(?(\\w+)?\\)?:\\s?(.*)\"\n\n[git]\nconventional_commits = true\n\n# Usage: git-cliff -o CHANGELOG.md\n# Generates changelog from conventional commits\n\n# Commit types:\n# feat:     New feature (MINOR)\n# fix:      Bug fix (PATCH)\n# BREAKING: Breaking change (MAJOR)\n# chore:    Maintenance (no release)\n# docs:     Documentation (no release)","description":"git-cliff configuration for automated changelog generation from conventional commits."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is release management?","options":["Writing code","Planning and controlling software releases","Managing teams","Setting up servers"],"answer":1,"explanation":"Release management plans, schedules, controls, and deploys software releases across environments."},{"question":"What does MAJOR version change indicate?","options":["Bug fix","Breaking/incompatible API changes","New backward-compatible feature","Documentation update"],"answer":1,"explanation":"MAJOR version increments indicate breaking changes that are not backward-compatible."},{"question":"What is a release gate?","options":["A security tool","A checkpoint a release must pass","A deployment tool","A code editor"],"answer":1,"explanation":"A release gate is a checkpoint that validates quality, security, or approval before proceeding."},{"question":"Release Management — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Release Management — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Release Management — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Release Management — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Release Management — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Release Management — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Release Management — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["devops-fundamentals"]["devops-change-mgmt"] = {"id":"devops-change-mgmt","title":"Change Management","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Change management in DevOps is the process of controlling and managing changes to IT systems, applications, and infrastructure.","Traditional ITIL change management is slow and bureaucratic (Change Advisory Board meetings). DevOps change management emphasizes automation, peer review, and continuous verification.","Key changes in DevOps: pre-approved standard changes (CI/CD), automated policy enforcement, smaller/frequent changes, peer review via PRs, monitoring-based verification.","DevOps change management reduces risk through frequency — small, frequent changes are easier to review, test, and rollback than large, infrequent ones."],"laymanDefinition":"Traditional change management is like getting a committee to approve any change to your house — paint color, new furniture, even changing a lightbulb needs sign-off. DevOps change management is like having building codes (automated policies) — you can repaint your room any time, as long as you follow the rules, and the inspector (CI) checks after you're done.","deepDive":[{"heading":"Traditional vs DevOps Change Management","text":"Traditional: CAB (Change Advisory Board) approvals, change windows (weekend nights), large releases, manual procedures, paper trails. DevOps: automated approvals from CI/CD, no change windows (continuous), small frequent releases, PR-based review, infrastructure as code, automated compliance checks."},{"heading":"Standard vs Normal Changes","text":"Standard: low-risk, pre-approved (config changes, dependency updates, routine deployments). Go through CI/CD automatically. Normal: higher risk, may need manual approval (architecture changes, database schema changes, security policy changes). DevOps philosophy: make as many changes \"standard\" as possible."},{"heading":"Automated Change Management","text":"CI/CD pipeline: any change passing pipeline = approved for deployment. Policy as Code: OPA/Kyverno enforce policies automatically. Git: every change is tracked, auditable, and reversible. Peer review: PRs ensure at least one person reviews each change. Monitoring: detects change-related issues automatically."},{"heading":"Change Management Best Practices","text":"Make changes small and frequent. Automate everything possible. Use peer review for every change. Monitor changes for impact. Document changes in Git (commit messages). Have automated rollback. Track change metrics: deployment frequency, change failure rate, MTTR. Use feature flags for risky changes."},{"heading":"Change Failure Rate (DORA Metric)","text":"Percentage of changes that result in degraded service or require remediation. Elite performers: 0-5%. Low performers: 16-30%. DevOps change management aims to reduce this through automation, testing, and small changes. Not all changes should be equal — high-risk changes get more scrutiny."}],"interviewAnswer":"DevOps change management is about automation, not bureaucracy. Make changes small and frequent. Use PRs for peer review. Let CI/CD be the approval process. Use policy as code for guardrails. Monitor every change. The goal is to enable velocity while maintaining safety through automation.","interviewQuestions":[{"question":"What is change management in DevOps?","answer":"Controlling and managing changes to IT systems with automation, peer review, and continuous verification."},{"question":"How is DevOps change management different from traditional?","answer":"DevOps: automated, continuous, small changes, PR-based. Traditional: CAB approvals, change windows, large releases."},{"question":"What is a standard change?","answer":"A low-risk, pre-approved change that can go through CI/CD automatically without manual approval."},{"question":"What is change failure rate?","answer":"A DORA metric measuring the percentage of changes that cause degraded service or require remediation."},{"question":"How does Git help change management?","answer":"Every change is tracked, auditable, reversible. Commits document who changed what and why."},{"question":"What is the goal of DevOps change management?","answer":"Enable velocity while maintaining safety through automation, not slow down changes with bureaucracy."},{"question":"Change Management — What security considerations apply here?","answer":"Security considerations include access control, encryption of sensitive data, and audit logging."},{"question":"Change Management — What best practices should be followed?","answer":"Best practices include version control, automation, monitoring, and thorough documentation."},{"question":"Change Management — How does this affect team collaboration?","answer":"It supports collaboration through shared visibility, standardized processes, and clear workflows."},{"question":"Change Management — What metrics indicate successful implementation?","answer":"Key metrics include adoption rate, error reduction, build times, and team satisfaction scores."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Change Management</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Standard Changes</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Pre-approved, CI/CD</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Normal Changes</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">May need approval</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Peer Review</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">PRs for every change</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Policy as Code</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated guardrails</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Monitoring</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Detect change impact</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Change Management</text><text x=\"385\" y=\"162\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">DevOps: small, frequent, automated</text><text x=\"385\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">, reviewed. Traditional: slow, bur</text><text x=\"385\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">eaucratic, large releases.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Change Management: Controlled, automated changes. </text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Small + frequent = safe. PRs + CI/CD + monitoring.</text></svg>","codeExamples":[{"title":"PR-Based Change Approval","useCase":"GitHub branch protection.","code":"# .github/CODEOWNERS — required reviewers\n* @team-leads\nsrc/db/* @db-admins\ninfra/* @platform-team\nsecurity/* @security-team\n\n# GitHub branch protection rules (UI)\n# - Require PR for main branch\n# - Require at least 1 review\n# - Require status checks (CI passes)\n# - Require up-to-date branches\n# - Require linear history\n# - Include administrators\n\n# These rules ensure every change is:\n# 1. Reviewed by peers\n# 2. Validated by CI\n# 3. Approved by code owners for sensitive files\n# 4. Traceable in Git history","description":"Branch protection rules enforce peer review and CI validation for every code change."},{"title":"Automated Change Logging","useCase":"Track all changes automatically.","code":"# Track changes via Git commits\n# Every commit = a recorded change\n\n# Generate change summary for compliance\ngit log --oneline --since=\"2024-01-01\"\n\n# Show all changes to a specific file\ngit log --oneline -- src/config/database.ts\n\n# Show who approved each PR\ngh pr list --state merged --search \"merged:>2024-01-01\"\n  --json number,title,author,mergedAt,reviews\n\n# Audit trail for compliance:\n# - Who made the change (committer)\n# - Who reviewed (PR reviewers)\n# - What changed (diff)\n# - When (timestamp)\n# - Why (commit message)\n# - Pipeline status (CI passing)","description":"Git and GitHub provide complete audit trail for change management compliance."},{"title":"Advanced Configuration","useCase":"Complex scenario","code":"# Advanced pattern for complex scenarios\n# Includes error handling","description":"Advanced configuration example."},{"title":"Integration Pattern","useCase":"Tool integration","code":"# Integration with other tools\n# Shows how components connect","description":"Integration example with related tools."}],"mcqQuestions":[{"question":"What is a key difference between DevOps and traditional change management?","options":["DevOps is slower","DevOps uses automation and small frequent changes","Traditional is faster","No difference"],"answer":1,"explanation":"DevOps change management uses automation, small frequent changes, and peer review instead of bureaucratic approvals."},{"question":"What is a standard change?","options":["Any change to production","Low-risk, pre-approved change","Emergency hotfix","Database migration"],"answer":1,"explanation":"A standard change is low-risk and pre-approved to go through CI/CD without manual approval."},{"question":"What DORA metric is related to change management?","options":["Deployment frequency","Change failure rate","Lead time","MTTR"],"answer":1,"explanation":"Change failure rate measures the percentage of changes causing degraded service or requiring remediation."},{"question":"Change Management — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Change Management — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Change Management — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Change Management — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Change Management — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Change Management — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Change Management — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};